import type { ExamQuestion } from "./types";

export const rnArrhythmiasChdAnticoagCatQuestions: ExamQuestion[] = [
  // ===== ATRIAL FIBRILLATION CAT (15 questions) =====
  { q: "A nurse is caring for four clients on a telemetry unit. Which client requires the MOST immediate intervention?\n\n1. Client with chronic AFib: HR 78, INR 2.4, no symptoms\n2. Client with new-onset AFib: HR 164, BP 76/48, diaphoretic, confused\n3. Client with AFib on metoprolol: HR 88, reports mild fatigue\n4. Client with paroxysmal AFib: in normal sinus rhythm, awaiting discharge", o: ["Client 1: Stable chronic AFib with therapeutic INR", "Client 2: New-onset AFib with hemodynamic instability requiring immediate synchronized cardioversion", "Client 3: Rate-controlled AFib with mild side effect", "Client 4: Stable paroxysmal AFib in sinus rhythm"], a: 1, r: "Client 2 demonstrates hemodynamic instability (hypotension, AMS, diaphoresis) requiring immediate synchronized cardioversion per ACLS. Unstable tachyarrhythmias take priority over all stable patients.", s: "Arrhythmias" },
  { q: "A client with AFib has CHA2DS2-VASc score 4 and HAS-BLED score 4. Which nursing assessment is MOST critical to communicate to the provider?", o: ["Dietary preferences", "History of falls, current NSAIDs, and recent BP trends — modifiable bleeding risk factors", "Exercise tolerance", "Sleep patterns"], a: 1, r: "High HAS-BLED identifies modifiable factors: falls (ICH risk), NSAIDs (additive bleeding), uncontrolled HTN. These inform anticoagulation risk-benefit analysis.", s: "Arrhythmias" },
  { q: "A nurse assesses a client 24 hours post-cardioversion for AFib on apixaban. Which finding requires immediate intervention?", o: ["HR 72 in sinus rhythm", "New-onset right arm weakness, facial droop, slurred speech", "Mild chest redness at pad sites", "BP 128/78"], a: 1, r: "New neurological deficits after cardioversion = cardioembolic stroke from dislodged LA thrombus. Activate stroke protocol immediately.", s: "Arrhythmias" },
  { q: "A client with persistent AFib, EF 30%, NYHA Class III HF is being evaluated for rhythm vs rate control. Which consideration is MOST important?", o: ["Rate control always preferred in HF", "Amiodarone is the only safe antiarrhythmic in severe HF; catheter ablation may improve cardiac function in HFrEF", "All antiarrhythmics safe in HF", "CCBs are first-line"], a: 1, r: "In HFrEF with AFib, amiodarone is the only safe antiarrhythmic (Class IC and sotalol contraindicated). Catheter ablation shows mortality benefit. Non-DHP CCBs are contraindicated.", s: "Arrhythmias" },
  { q: "A client on warfarin for AFib presents with INR 8.2, severe epistaxis, and oozing from IV sites. Which intervention sequence is correct?", o: ["Hold warfarin and recheck INR tomorrow", "Hold warfarin, give IV vitamin K AND 4-factor PCC for immediate reversal, apply pressure to bleeding sites", "Only give oral vitamin K", "Increase warfarin dose"], a: 1, r: "INR >5 with active significant bleeding: hold warfarin + IV vitamin K (6-8 hour onset) + 4-factor PCC (immediate factor replacement). Both are needed — vitamin K alone is too slow.", s: "Arrhythmias" },
  { q: "Three clients need ECG interpretation. Prioritize:\n1. Irregularly irregular rhythm, no P waves, HR 88, stable\n2. Regular sawtooth pattern, HR 150, lightheaded\n3. Wide QRS tachycardia, HR 180, no pulse palpable", o: ["Client 1 — needs anticoagulation assessment", "Client 3 — pulseless VTach/VFib requires immediate defibrillation and CPR", "Client 2 — needs adenosine", "All can wait for cardiology"], a: 1, r: "Pulseless wide-complex tachycardia = cardiac arrest requiring immediate defibrillation/CPR. This is the most time-critical. Client 2 (probable flutter with symptoms) is next priority. Client 1 (controlled AFib) is stable.", s: "Arrhythmias" },
  { q: "A client with new AFib is started on rivaroxaban and metoprolol. What assessment finding at the 2-week follow-up visit would concern the nurse MOST?", o: ["HR 84 bpm at rest", "Client reports taking rivaroxaban without food", "Mild fatigue in the afternoon", "Weight has been stable"], a: 1, r: "Rivaroxaban 20 mg must be taken WITH food (increases bioavailability by 39%). Without food, the drug may not achieve therapeutic levels, leaving the client at risk for stroke.", s: "Arrhythmias" },
  { q: "A client with AFib on apixaban requires emergency appendectomy. The last apixaban dose was 4 hours ago. What does the nurse anticipate?", o: ["Proceed with surgery without reversal", "Andexanet alfa or 4-factor PCC for Xa inhibitor reversal prior to emergency surgery", "Wait 48 hours for clearance", "Give vitamin K"], a: 1, r: "With last dose 4 hours ago, apixaban is at peak levels. Emergency surgery requires reversal: andexanet alfa (specific) or 4-factor PCC (off-label). Cannot wait for natural clearance.", s: "Arrhythmias" },
  { q: "A nurse is evaluating a client with AFib who has been on amiodarone for 2 years. Which monitoring is MOST critical at this appointment?", o: ["Blood glucose", "Thyroid function (TSH), pulmonary function, liver function, and ophthalmologic exam — amiodarone causes multi-organ toxicity", "Urine culture", "Bone density scan"], a: 1, r: "Amiodarone long-term toxicities require monitoring: thyroid (hypo/hyperthyroidism from iodine content), pulmonary fibrosis, hepatotoxicity, corneal deposits. All should be checked at least annually.", s: "Arrhythmias" },
  { q: "A client with paroxysmal AFib is considering catheter ablation vs lifelong medications. What information is MOST important for the nurse to share?", o: ["Ablation always cures AFib permanently", "Ablation success is 60-80% for paroxysmal AFib; may need repeat procedure; anticoagulation decisions still based on CHA2DS2-VASc regardless of rhythm", "Medications are always better", "Ablation eliminates the need for any follow-up"], a: 1, r: "Realistic expectation setting: ablation has good but not perfect success rates, may need repeat, and anticoagulation is based on stroke risk factors — not whether the patient is in sinus rhythm.", s: "Arrhythmias" },
  { q: "A client with AFib RVR (HR 156) and HFrEF (EF 25%) needs rate control. Which medication should the nurse question if ordered?", o: ["IV metoprolol", "IV diltiazem — non-DHP CCBs are contraindicated in HFrEF due to negative inotropy", "IV amiodarone", "Digoxin"], a: 1, r: "Diltiazem and verapamil are contraindicated in HFrEF because they suppress cardiac contractility. Use IV metoprolol (carefully), IV amiodarone, or digoxin instead.", s: "Arrhythmias" },
  { q: "A client with chronic AFib develops sudden hemoptysis on warfarin. INR is 3.8. What is the nurse's priority sequence?", o: ["Recheck INR in 24 hours", "Hold warfarin, apply direct pressure if possible, assess airway patency, notify provider STAT, anticipate reversal agents and bronchoscopy", "Continue warfarin", "Give more warfarin"], a: 1, r: "Hemoptysis on anticoagulation with elevated INR: hold anticoagulant, secure airway, notify provider urgently. May need reversal (IV vitamin K, PCC) and bronchoscopy to identify and treat the source.", s: "Arrhythmias" },
  { q: "A nurse discovers that a client with AFib has been taking both warfarin and ibuprofen daily for arthritis. What is the priority concern?", o: ["No concern", "Ibuprofen increases bleeding risk through additive antiplatelet effect AND GI erosion while also potentially altering warfarin metabolism", "Ibuprofen treats AFib", "Only check INR"], a: 1, r: "NSAIDs with warfarin: double bleeding risk from antiplatelet effect + GI mucosal damage. Also, some NSAIDs inhibit warfarin metabolism. Educate about safer alternatives (acetaminophen).", s: "Arrhythmias" },
  { q: "A client converted from AFib to sinus rhythm 3 weeks ago asks if anticoagulation can be stopped. CHA2DS2-VASc is 5. What is the nurse's best response?", o: ["Yes, you are in sinus rhythm now", "No — anticoagulation is based on stroke risk factors, not current rhythm. With a score of 5, lifelong anticoagulation is recommended regardless of rhythm", "Only take it on weekends", "Switch to aspirin"], a: 1, r: "Anticoagulation decision is based on CHA2DS2-VASc score, not current rhythm. Paroxysmal AFib can recur asymptomatically. With score 5, lifelong OAC is strongly recommended.", s: "Arrhythmias" },
  { q: "A client with AFib on metoprolol and apixaban is hospitalized for pneumonia with fever 102°F. HR has increased from usual 78 to 134. The nurse should prioritize which assessment?", o: ["Immediately increase metoprolol", "Assess whether the rate increase is appropriate compensatory response to fever/infection vs loss of rate control requiring intervention", "Cardiovert immediately", "Add diltiazem"], a: 1, r: "In acute illness, tachycardia is often a compensatory response. Assess the clinical picture: if HR is proportional to fever/infection, treat the fever/infection. If disproportionate or symptomatic, rate control adjustment may be needed.", s: "Arrhythmias" },

  // ===== ATRIAL FLUTTER CAT (15 questions) =====
  { q: "A client has a regular narrow-complex tachycardia at exactly 150 bpm. Two other nurses believe it is sinus tachycardia. What clinical reasoning should guide the nurse's assessment?", o: ["Agree with colleagues — 150 bpm is typical sinus tach", "Regular tachycardia at exactly 150 bpm should ALWAYS raise suspicion for atrial flutter with 2:1 conduction; request adenosine to unmask flutter waves", "Order CXR", "Give beta-blocker immediately"], a: 1, r: "150 bpm is the classic 'red flag' rate for flutter with 2:1 conduction (300/2). Adenosine can transiently block AV conduction to reveal flutter waves. This diagnostic consideration prevents missed diagnoses.", s: "Arrhythmias" },
  { q: "A client with typical atrial flutter is being considered for catheter ablation vs long-term antiarrhythmic therapy. What information guides this decision?", o: ["Antiarrhythmics are always preferred", "CTI ablation has >95% success rate with low complications, making it the preferred definitive treatment for typical flutter over lifelong medications", "Ablation is experimental", "Both have equal outcomes"], a: 1, r: "For typical (CTI-dependent) flutter, ablation is preferred over long-term medications due to very high success rate (>95%), low complication rate, and avoidance of medication side effects.", s: "Arrhythmias" },
  { q: "A client with flutter post-CTI ablation develops AFib 6 months later. The client is upset that 'the ablation didn't work.' How should the nurse respond?", o: ["The ablation failed", "Flutter and AFib are different arrhythmias that often coexist. The flutter ablation was successful; AFib is a separate condition requiring its own management plan", "Repeat the same ablation", "The doctor made an error"], a: 1, r: "Flutter and AFib frequently coexist. CTI ablation cures flutter specifically but doesn't prevent AFib (different mechanism). Many flutter patients eventually develop AFib requiring separate treatment.", s: "Arrhythmias" },
  { q: "A client with atrial flutter starts flecainide WITHOUT a concurrent AV nodal blocking agent. The nurse notes the ventricular rate increases from 150 to 220 bpm. What happened?", o: ["Expected improvement", "Flecainide slowed the atrial rate from 300 to 220 bpm, allowing 1:1 AV conduction — a dangerous complication of class IC drugs used alone for flutter", "Equipment malfunction", "Unrelated tachycardia"], a: 1, r: "Flecainide slowed the atrial flutter rate enough for 1:1 conduction through the AV node, creating a dangerously fast ventricular rate. This is why AV nodal blockers MUST accompany class IC drugs.", s: "Arrhythmias" },
  { q: "A nurse must prioritize three flutter patients:\n1. Flutter with 4:1 block, HR 75, asymptomatic, on anticoagulation\n2. Flutter with 2:1 block, HR 150, lightheaded, BP 96/60\n3. Flutter with variable block, HR 100, mild palpitations", o: ["Client 1 — needs ablation scheduling", "Client 2 — symptomatic with hemodynamic compromise requiring urgent rate control or cardioversion", "Client 3 — needs rate control", "All are equally urgent"], a: 1, r: "Client 2 has hemodynamic compromise (lightheadedness, borderline hypotension) requiring urgent intervention. Client 3 is mildly symptomatic. Client 1 is stable and asymptomatic.", s: "Arrhythmias" },
  { q: "A client with flutter is started on dofetilide. On day 2 of hospital initiation, the QTc increases from 440 ms to 520 ms. What action is required?", o: ["Continue dofetilide — QT prolongation is expected", "Hold dofetilide — QTc >500 ms requires holding the drug due to Torsades risk", "Increase dofetilide dose", "No monitoring needed"], a: 1, r: "QTc >500 ms on dofetilide = hold the drug immediately. Risk of Torsades de Pointes. This is why FDA mandates dofetilide initiation in hospital with continuous telemetry ≥3 days.", s: "Arrhythmias" },
  { q: "A post-cardiac surgery patient develops an irregular atrial tachycardia at 240 bpm. What type of flutter is this most likely?", o: ["Typical CTI-dependent flutter", "Atypical (incisional) flutter — reentry around surgical scar tissue; requires complex mapping if ablation is considered", "Sinus tachycardia", "VTach"], a: 1, r: "Post-surgical flutter is typically atypical, using circuits around surgical scar lines rather than the CTI. Standard CTI ablation will not work; 3D electroanatomic mapping is needed.", s: "Arrhythmias" },
  { q: "A client with flutter on IV diltiazem has a rate that dropped from 150 to 100 bpm. The nurse notes the rhythm remains regular. What is the clinical interpretation?", o: ["Flutter converted to sinus", "The conduction ratio likely changed from 2:1 to 3:1 — the atrial rate is still ~300 bpm, but fewer impulses are conducted", "Client developed heart block", "Diltiazem cured the flutter"], a: 1, r: "Rate change from 150 to 100 with maintained regularity suggests the conduction ratio shifted from 2:1 (300/2=150) to 3:1 (300/3=100). Flutter persists but the ventricular rate is better controlled.", s: "Arrhythmias" },
  { q: "A client with chronic atrial flutter has been rate-controlled with diltiazem for 5 years. Recent echo shows progressive RV dilation. What does this suggest?", o: ["Normal aging", "Chronic flutter is causing persistent RV volume overload; reassess for rhythm control strategy (ablation) to prevent further remodeling", "Diltiazem side effect", "Unrelated finding"], a: 1, r: "Chronic flutter, even when rate-controlled, can cause progressive atrial/ventricular remodeling. RV dilation suggests the long-term hemodynamic burden warrants consideration of rhythm control via ablation.", s: "Arrhythmias" },
  { q: "A nurse is preparing a client for elective cardioversion of atrial flutter. The client has been on apixaban for 4 weeks. What must be verified?", o: ["Nothing needs verification", "Verify the client has been taking apixaban consistently as prescribed — missed doses mean inadequate anticoagulation despite time elapsed", "Only check INR", "Check aPTT"], a: 1, r: "DOACs require consistent adherence for adequate anticoagulation. Unlike warfarin (checked via INR), DOAC compliance must be assessed through patient history. Missed doses = inadequate anticoagulation = cardioversion risk.", s: "Arrhythmias" },
  { q: "A client asks about the difference between atrial flutter and AFib for their condition management. What is the MOST important clinical distinction?", o: ["No practical difference", "Flutter is a single organized circuit treatable with high-success ablation, while AFib involves multiple disorganized circuits with lower ablation success; both require anticoagulation", "AFib is always worse", "Flutter doesn't need treatment"], a: 1, r: "The key distinction: flutter is a single organized reentry circuit highly amenable to CTI ablation (>95%). AFib is more complex with lower ablation success. Both carry stroke risk requiring anticoagulation.", s: "Arrhythmias" },
  { q: "A client with atrial flutter is scheduled for cardioversion. TEE shows a small thrombus in the left atrial appendage. What should the nurse anticipate?", o: ["Proceed with cardioversion", "Cancel cardioversion, continue anticoagulation for at least 3-4 more weeks, repeat TEE to confirm thrombus resolution before attempting cardioversion", "Immediate surgery", "Switch to aspirin"], a: 1, r: "LAA thrombus = absolute contraindication to cardioversion (risk of stroke). Continue therapeutic anticoagulation to dissolve the thrombus, then repeat TEE. Only proceed when thrombus-free.", s: "Arrhythmias" },
  { q: "A client with flutter who recently started amiodarone develops HR 52 with fatigue. What is the nurse's clinical reasoning?", o: ["Expected therapeutic effect", "Amiodarone has potent AV and SA nodal blocking effects that can cause excessive bradycardia — may need dose adjustment or alternative strategy", "Normal aging", "Check blood glucose"], a: 1, r: "Amiodarone has broad electrophysiologic effects including SA and AV nodal depression. Combined with flutter's variable conduction, excessive bradycardia can occur. Assess symptoms and discuss dose adjustment.", s: "Arrhythmias" },
  { q: "Two clients with atrial flutter:\n1. Typical flutter: CTI-dependent, first occurrence\n2. Atypical flutter: left atrial scar-related, post-MAZE surgery\nWhich client's management is more straightforward and why?", o: ["Both are identical", "Client 1 — typical flutter has predictable CTI circuit with >95% ablation success; Client 2's atypical circuit requires complex 3D mapping with lower success rates", "Client 2 is simpler", "Neither can be treated"], a: 1, r: "Typical flutter's well-defined CTI circuit allows straightforward ablation. Atypical post-surgical flutter involves unpredictable scar-related circuits requiring advanced electrophysiology mapping.", s: "Arrhythmias" },
  { q: "A client with flutter on anticoagulation asks why they need anticoagulation when their heart rhythm is 'organized unlike AFib.' What is the best evidence-based response?", o: ["You're right, you don't need it", "Despite organized contractions, flutter patients have equivalent stroke risk to AFib because most flutter patients also develop AFib, and stasis still occurs at high atrial rates", "Only take it sometimes", "We're not sure why"], a: 1, r: "Same CHA2DS2-VASc guidelines apply. Most flutter patients also develop AFib (coexistence is very common). Additionally, rapid atrial rates can still cause blood stasis. Evidence supports equal anticoagulation.", s: "Arrhythmias" },

  // ===== SVT CAT (15 questions) =====
  { q: "A nurse has three clients with SVT:\n1. SVT HR 200, BP 110/70, mild palpitations\n2. SVT HR 188, BP 78/42, chest pain, diaphoresis\n3. SVT HR 180, converted with vagal maneuver, now in sinus rhythm\nWhich client needs MOST immediate attention?", o: ["Client 1 — fastest rate", "Client 2 — hemodynamically unstable requiring immediate synchronized cardioversion", "Client 3 — just converted", "All need equal attention"], a: 1, r: "Client 2 is hemodynamically unstable (severe hypotension, chest pain, diaphoresis) requiring immediate synchronized cardioversion. Client 1 is stable for vagal maneuvers/adenosine. Client 3 has already converted.", s: "Arrhythmias" },
  { q: "A client with recurrent SVT declines catheter ablation. The provider prescribes verapamil for prophylaxis. What is the nurse's MOST important assessment before starting?", o: ["Blood glucose", "Confirm the client does NOT have WPW pattern on baseline ECG — verapamil is contraindicated with accessory pathways", "Urine output", "Bowel sounds"], a: 1, r: "Verapamil (AV nodal blocker) is contraindicated in WPW. If the client has an accessory pathway, AV blockade allows unopposed accessory conduction with risk of VFib. Baseline ECG must rule out delta waves.", s: "Arrhythmias" },
  { q: "A nurse is administering adenosine 6 mg for SVT. The drug is given slowly over 30 seconds through a hand IV. The SVT does not terminate. What is the most likely reason for failure?", o: ["Adenosine doesn't work for SVT", "The ultra-short half-life (<10 seconds) means the drug was metabolized before reaching the heart — must be given as rapid IV push through a proximal large-bore IV", "Dose was too high", "The client is allergic"], a: 1, r: "Adenosine failure is most commonly due to slow administration or distal IV site. The 10-second half-life requires rapid push (1-2 sec) through antecubital IV with immediate 20 mL flush.", s: "Arrhythmias" },
  { q: "A client with asthma develops SVT. Vagal maneuvers fail. Adenosine is contraindicated. What alternative does the nurse anticipate?", o: ["More aggressive vagal maneuvers", "IV diltiazem or IV metoprolol as alternative for terminating SVT when adenosine is contraindicated", "Defibrillation", "No treatment available"], a: 1, r: "Adenosine can trigger bronchospasm in asthmatics via A1 receptor stimulation. IV diltiazem is the preferred alternative for stable SVT in asthmatic patients.", s: "Arrhythmias" },
  { q: "A client with SVT asks why the nurse is recording the ECG during adenosine administration. What is the BEST explanation?", o: ["It's just routine documentation", "The rhythm strip captures the moment of conversion and reveals the underlying rhythm mechanism, which helps determine long-term treatment planning", "To check for allergic reaction", "No real reason"], a: 1, r: "The ECG during adenosine provides critical diagnostic information: reveals the SVT mechanism (AVNRT vs AVRT), unmasks any underlying atrial activity (flutter, AFib), and guides decisions about long-term management.", s: "Arrhythmias" },
  { q: "A young healthy client has a third SVT episode in 6 months. Each episode self-terminates within 30 minutes. What long-term management should the nurse discuss?", o: ["No discussion needed", "Catheter ablation should be discussed as a curative option with >95% success rate, versus lifelong medications with side effects", "Only emergency treatment needed", "Increase caffeine to prevent episodes"], a: 1, r: "Recurrent symptomatic SVT warrants discussion of definitive management. Ablation (>95% cure rate for AVNRT/AVRT) vs daily medications (side effects, ongoing episodes). Patient preference is important.", s: "Arrhythmias" },
  { q: "A client on theophylline for COPD develops SVT. Adenosine 6 mg and 12 mg both fail. What drug interaction explains this?", o: ["No interaction exists", "Theophylline is a methylxanthine that competitively antagonizes adenosine receptors, reducing adenosine effectiveness", "Theophylline potentiates adenosine", "COPD prevents adenosine from working"], a: 1, r: "Theophylline and caffeine are adenosine receptor antagonists. Higher adenosine doses may be needed, or alternative agents (IV diltiazem) should be used.", s: "Arrhythmias" },
  { q: "A nurse is teaching the modified Valsalva technique to a client with recurrent SVT. What key modification makes it more effective than standard Valsalva?", o: ["Straining for longer", "After straining for 15 seconds in semi-recumbent position, immediately lie supine with legs elevated 45° — this augments vagal tone through increased venous return", "Standing upright during strain", "Straining less forcefully"], a: 1, r: "The postural modification (supine with legs up after straining) significantly increases venous return and augments the vagal response, approximately doubling the conversion rate compared to standard Valsalva.", s: "Arrhythmias" },
  { q: "A client with SVT and WPW develops wide-complex tachycardia at 250 bpm. The prior nurse gave IV diltiazem. The client's BP drops to 60/40. What likely happened?", o: ["Normal response to diltiazem", "Diltiazem blocked AV nodal conduction allowing rapid accessory pathway conduction, creating antidromic AVRT with hemodynamic collapse — AV blockers are contraindicated in WPW", "Allergic reaction", "Equipment error"], a: 1, r: "AV nodal blockers in WPW are CONTRAINDICATED because they force conduction through the unblocked accessory pathway at dangerously fast rates. This can cause VFib and death. Use procainamide or cardioversion.", s: "Arrhythmias" },
  { q: "A client's SVT consistently terminates with adenosine but recurs within hours. The client asks 'why doesn't adenosine fix this permanently?' Best response?", o: ["Adenosine should cure it", "Adenosine terminates the current episode by transiently blocking the AV node, but the underlying reentry circuit persists. Catheter ablation is the only way to permanently eliminate the circuit", "Take adenosine daily", "We don't know why it recurs"], a: 1, r: "Adenosine works by transiently blocking AV conduction (terminates current circuit) but the dual pathways or accessory pathway remain. Ablation destroys the substrate for permanent cure.", s: "Arrhythmias" },
  { q: "An infant with SVT (HR 300) is cyanotic and has poor perfusion. Vagal maneuvers (ice to face) failed. What is the next intervention?", o: ["Wait for spontaneous termination", "Rapid IV adenosine; if not available or fails, immediate synchronized cardioversion at 0.5-1 J/kg", "Defibrillation at maximum energy", "Oral metoprolol"], a: 1, r: "Hemodynamically compromised infant with SVT: IV adenosine (0.1 mg/kg rapid push). If unavailable or fails, synchronized cardioversion 0.5-1 J/kg. Infants tolerate SVT poorly due to limited cardiac reserve.", s: "Arrhythmias" },
  { q: "A nurse notices a 'pseudo-R prime' in V1 during SVT. What does this finding suggest about the SVT mechanism?", o: ["Normal ECG variant", "AVNRT — retrograde P waves buried in the QRS create the pseudo-R' appearance, confirming near-simultaneous atrial/ventricular activation via the fast pathway", "Indicates VTach", "Equipment artifact"], a: 1, r: "Pseudo-R' in V1 is a classic AVNRT clue. Retrograde P waves (traveling up the fast pathway simultaneously with ventricular activation) distort the terminal portion of QRS, creating this appearance.", s: "Arrhythmias" },
  { q: "A client has SVT with HR 180 and BP 80/50 after vagal maneuvers fail. The nurse prepares adenosine, but the only available IV is a foot IV. What is the best approach?", o: ["Give adenosine through the foot IV", "Proceed directly to synchronized cardioversion — distal IV will not deliver adenosine effectively due to ultrashort half-life", "Wait for a new IV", "Give adenosine IM"], a: 1, r: "With a distal IV and hemodynamic instability, adenosine is unlikely to reach the heart before metabolism. The unstable hemodynamics alone (BP 80/50) warrant immediate synchronized cardioversion.", s: "Arrhythmias" },
  { q: "A client successfully treated with ablation for AVNRT 1 year ago presents with a different SVT pattern. ECG shows long RP tachycardia. What should the nurse understand?", o: ["The ablation failed", "The client may have a different SVT mechanism (e.g., atypical AVNRT or AVRT) that was not addressed by the original ablation targeting typical AVNRT", "This is impossible", "Repeat the same ablation"], a: 1, r: "Different SVT mechanisms can coexist. A client ablated for typical AVNRT (short RP) presenting with long RP tachycardia may have atypical AVNRT, AVRT, or atrial tachycardia — a different substrate requiring re-evaluation.", s: "Arrhythmias" },
  { q: "A nurse is evaluating two clients with SVT for discharge readiness:\n1. Client converted with vagal maneuver, first episode, young and healthy, no WPW\n2. Client converted with adenosine, third episode this month, on no prophylactic meds\nWhat is the appropriate disposition?", o: ["Both can be discharged identically", "Client 1 may be safe for discharge with outpatient follow-up; Client 2 needs prophylactic medication or ablation referral before discharge to prevent dangerous recurrences", "Both need admission", "Neither needs follow-up"], a: 1, r: "Recurrent SVT (Client 2) needs a management plan before discharge: prophylactic medication (beta-blocker, CCB) or ablation referral. Single first episode (Client 1) with low-risk features may safely follow up outpatient.", s: "Arrhythmias" },

  // ===== VENTRICULAR TACHYCARDIA CAT (15 questions) =====
  { q: "A nurse encounters four clients simultaneously:\n1. Pulseless VTach\n2. Stable monomorphic VTach HR 140, BP 100/60\n3. Torsades de Pointes with pulse, QTc 620\n4. NSVT (4-beat run) on telemetry, asymptomatic\nPrioritize interventions.", o: ["All need the same treatment", "Client 1 first (immediate defibrillation/CPR), then Client 3 (IV magnesium), then Client 2 (IV amiodarone), then Client 4 (monitoring/evaluation)", "Client 4 first", "Client 2 first"], a: 1, r: "Priority: (1) Pulseless VTach = cardiac arrest, immediate defibrillation + CPR. (2) Torsades with pulse is unstable and needs IV magnesium urgently. (3) Stable VTach can wait briefly for amiodarone. (4) NSVT can be monitored.", s: "Arrhythmias" },
  { q: "A client on haloperidol and ondansetron develops polymorphic VTach with QTc 580 ms. What is the MOST important intervention beyond IV magnesium?", o: ["Continue both medications", "Stop ALL QT-prolonging medications immediately — both haloperidol and ondansetron contribute to QT prolongation and Torsades risk", "Increase haloperidol", "Add amiodarone"], a: 1, r: "Drug-induced Torsades: stop all QT-prolonging agents. Both haloperidol and ondansetron prolong QT. Amiodarone is CONTRAINDICATED (it also prolongs QT). Give magnesium, consider overdrive pacing.", s: "Arrhythmias" },
  { q: "A post-MI client with EF 25% has a 12-beat run of NSVT on telemetry. The client is asymptomatic. What long-term management should the nurse anticipate?", o: ["No follow-up needed", "EF ≤35% with NSVT post-MI qualifies for ICD placement for primary prevention of sudden cardiac death", "Repeat ECG in 1 year", "Start amiodarone only"], a: 1, r: "NSVT + EF ≤35% post-MI indicates high SCD risk. Primary prevention ICD is indicated per guidelines. EP study may be performed. This is a life-saving intervention.", s: "Arrhythmias" },
  { q: "A wide-complex tachycardia at 160 bpm is on the monitor. The nurse cannot determine if it is VTach or SVT with aberrant conduction. What is the safest approach?", o: ["Treat as SVT with diltiazem", "Treat as VTach — amiodarone or cardioversion. It is ALWAYS safer to treat SVT as VTach than VTach as SVT", "Wait for 12-lead ECG", "Give adenosine"], a: 1, r: "Cardinal rule: when in doubt, treat as VTach. VTach treatment (amiodarone, cardioversion) is safe for SVT. Giving SVT drugs (CCBs) to VTach can cause cardiovascular collapse and death.", s: "Arrhythmias" },
  { q: "A client with an ICD has received 3 appropriate shocks in 2 hours. What is this called and what does the nurse anticipate?", o: ["Normal ICD function", "Ventricular storm — a cardiac emergency requiring ICU admission, IV antiarrhythmics, sedation, and evaluation for VT ablation", "ICD malfunction", "Replace battery"], a: 1, r: "≥3 VTach/VFib episodes in 24 hours = ventricular storm. Emergency: ICU, IV amiodarone/lidocaine, optimize electrolytes, beta-blockade, consider catheter ablation. Painful and psychologically distressing.", s: "Arrhythmias" },
  { q: "A client with VTach has K+ 3.1 and Mg2+ 1.2. Amiodarone infusion is running. What is the nurse's PRIORITY?", o: ["Continue amiodarone only", "Aggressively replace both potassium and magnesium — electrolyte correction is essential for VTach management and amiodarone effectiveness", "Restrict potassium", "Hold amiodarone"], a: 1, r: "Hypokalemia and hypomagnesemia are major VTach perpetuators. Correct both: K+ target >4.0 mEq/L, Mg2+ target >2.0 mEq/L. Without correction, antiarrhythmic therapy may be ineffective.", s: "Arrhythmias" },
  { q: "A client with sustained VTach and pulse has BP 70/40, AMS, and chest pain. The nurse prepares for synchronized cardioversion. The defibrillator is in synchronized mode, but the machine is not detecting R waves. What must the nurse do?", o: ["Shock anyway in synchronized mode", "Switch to unsynchronized (defibrillation) mode — if the machine cannot synchronize, an unsynchronized shock is safer than no shock in this critically unstable patient", "Wait for better R-wave detection", "Try a different lead"], a: 1, r: "If the defibrillator cannot synchronize (poor R-wave detection in VTach), switch to unsynchronized mode. In a critically unstable patient, delivering an unsynchronized shock is better than delaying treatment.", s: "Arrhythmias" },
  { q: "A young athlete with no structural heart disease develops VTach with LBBB morphology and inferior axis during exercise. What type of VTach is this likely?", o: ["Always dangerous ischemic VTach", "RVOT (right ventricular outflow tract) VTach — idiopathic VTach with generally benign prognosis, amenable to catheter ablation", "Must have underlying CAD", "This cannot happen in young athletes"], a: 1, r: "RVOT VTach: LBBB morphology with inferior axis in structurally normal heart, typically triggered by exercise. Idiopathic with better prognosis. Highly amenable to catheter ablation.", s: "Arrhythmias" },
  { q: "A client's ICD is delivering multiple inappropriate shocks. The client is in AFib RVR at 170 bpm (not VTach). What is the immediate nursing action?", o: ["Let shocks continue", "Place a magnet over the ICD to disable tachycardia therapy, confirm AFib on monitor, arrange urgent device reprogramming", "Remove the ICD", "Give amiodarone"], a: 1, r: "Inappropriate shocks from AFib RVR: magnet disables shock therapy (preserves pacing). Confirm the rhythm is AFib, not VTach. Arrange urgent device interrogation and reprogramming of discrimination algorithms.", s: "Arrhythmias" },
  { q: "A client develops polymorphic VTach with a NORMAL QTc. How does management differ from Torsades de Pointes?", o: ["Identical management", "Normal QT polymorphic VTach is often ischemia-related — treat with amiodarone (NOT contraindicated here) and evaluate for acute coronary syndrome", "Magnesium for both", "No treatment needed"], a: 1, r: "Critical distinction: polymorphic VTach with normal QT ≠ Torsades. Likely ischemic etiology. Amiodarone IS appropriate (unlike Torsades where it's contraindicated). Urgent cath for ACS evaluation.", s: "Arrhythmias" },
  { q: "A client with an ICD returns from MRI. The nurse notes the ICD was placed in 'MRI mode' before the scan. What must be done now?", o: ["Nothing — it reverts automatically", "The ICD must be reprogrammed back to active mode immediately after MRI — in MRI mode, tachyarrhythmia detection and therapy are suspended", "Leave in MRI mode", "Remove the ICD"], a: 1, r: "MRI mode suspends VTach/VFib detection and therapy. If the device is not reprogrammed back after the scan, the patient has NO ICD protection against lethal arrhythmias. This is time-critical.", s: "Arrhythmias" },
  { q: "A client on amiodarone for VTach suppression develops new thyroid function abnormalities. TSH is 0.01 (low). What complication has occurred?", o: ["Normal on amiodarone", "Amiodarone-induced thyrotoxicosis — excess thyroid hormone can worsen VTach and requires urgent endocrine management", "Hypothyroidism", "Unrelated finding"], a: 1, r: "Amiodarone contains 37% iodine. Can cause both hypo- and hyperthyroidism. Low TSH = thyrotoxicosis, which can exacerbate arrhythmias. Urgent endocrine consultation needed. May require amiodarone discontinuation.", s: "Arrhythmias" },
  { q: "During a VTach arrest, ETCO2 is 8 mmHg after 20 minutes of CPR despite good technique. What does this suggest?", o: ["CPR is excellent", "Very low ETCO2 (<10 mmHg) after 20 minutes of quality CPR suggests poor prognosis and may guide discussions about termination of resuscitation", "Patient is improving", "Need more epinephrine only"], a: 1, r: "ETCO2 <10 mmHg after 20 minutes despite quality CPR correlates with very low likelihood of ROSC. While not the sole determinant, it is one factor in the team decision about continuing resuscitation.", s: "Arrhythmias" },
  { q: "A client with VTach and cardiogenic shock is on IV amiodarone, vasopressors, and IABP. VTach persists despite maximum medical therapy. What intervention should the nurse anticipate?", o: ["Continue current therapy only", "Emergent catheter ablation for refractory VTach — ablation can eliminate the VTach substrate when medications fail", "Discharge planning", "Stop all medications"], a: 1, r: "Refractory VTach (electrical storm not responding to medications) is an indication for emergent VTach ablation. The ablation targets and destroys the scar-related reentry circuit causing the VTach.", s: "Arrhythmias" },
  { q: "A nurse is caring for a client post-cardiac arrest from VFib who achieved ROSC. The client is now on TTM at 33°C. What electrolyte change should the nurse expect during cooling?", o: ["Hyperkalemia", "Hypokalemia — as temperature drops, potassium shifts intracellularly, requiring replacement during cooling and monitoring for hyperkalemia during rewarming", "No electrolyte changes", "Hypercalcemia"], a: 1, r: "During cooling: K+ shifts intracellularly → hypokalemia (may need replacement). During rewarming: K+ shifts back extracellularly → risk of hyperkalemia. Monitor electrolytes closely during both phases.", s: "Arrhythmias" },

  // ===== VENTRICULAR FIBRILLATION CAT (15 questions) =====
  { q: "During a VFib arrest, the nurse notes the rhythm has become fine VFib after the third shock. The team leader suggests stopping resuscitation as the rhythm appears 'almost asystole.' What should the nurse advocate?", o: ["Agree — fine VFib is asystole", "Check multiple leads to confirm — fine VFib is still a shockable rhythm that may respond to defibrillation, CPR, and medications", "Stop CPR immediately", "Give more atropine"], a: 1, r: "Fine VFib may appear flat in one lead but show activity in others. Always check multiple leads. VFib is SHOCKABLE — asystole is not. Continuing resuscitation for fine VFib is appropriate.", s: "Arrhythmias" },
  { q: "A VFib arrest team is performing CPR. The compressor asks to continue beyond 2 minutes because 'I'm not tired yet.' Should the nurse allow this?", o: ["Yes, if the compressor feels fine", "No — rotate compressors every 2 minutes regardless of fatigue, as CPR quality deteriorates before the rescuer perceives fatigue", "Rotate every 5 minutes", "Only rotate if requested"], a: 1, r: "Research shows CPR quality (depth, rate, recoil) degrades after 2 minutes even when rescuers feel fine. Evidence-based guideline: rotate every 2 minutes. Don't rely on self-reported fatigue.", s: "Arrhythmias" },
  { q: "A client with VFib arrest has suspected acute MI as the cause. After ROSC, the team debates whether to perform cardiac catheterization given the client is comatose. What should the nurse understand?", o: ["Cath is contraindicated in comatose patients", "Post-ROSC STEMI requires emergent catheterization regardless of neurological status — early PCI improves survival", "Wait for neurological recovery", "Only treat the brain"], a: 1, r: "Post-ROSC STEMI: emergent catheterization and PCI regardless of consciousness level. Acute MI caused the arrest and will cause re-arrest if not treated. Simultaneous neuroprotection (TTM) continues.", s: "Arrhythmias" },
  { q: "During a VFib arrest, the team is delivering multiple shocks with prolonged pauses (>20 seconds) between compressions for rhythm analysis. What quality improvement issue should the nurse identify?", o: ["This is standard practice", "Excessive perishock pauses significantly reduce coronary perfusion pressure and worsen outcomes — pauses should be <10 seconds", "Pauses don't matter", "More pauses allow better rhythm analysis"], a: 1, r: "Every second without compressions drops CPP. Perishock pauses >10 seconds significantly worsen outcomes. Technique: charge during compressions, brief (<5 sec) pause for rhythm check and shock delivery.", s: "Arrhythmias" },
  { q: "A client in VFib arrest has an initial ETCO2 of 35 mmHg that drops to 12 mmHg after 5 minutes. What does this declining trend suggest?", o: ["Improvement", "Declining ETCO2 during arrest may indicate CPR quality deterioration, rescuer fatigue, or worsening hemodynamic status — reassess compression quality and consider team rotation", "Normal fluctuation", "Equipment error"], a: 1, r: "Declining ETCO2 during CPR is concerning. Most common cause: decreasing compression quality. Rotate compressors, verify technique. Could also indicate worsening hemodynamics or equipment issue.", s: "Arrhythmias" },
  { q: "A renal dialysis patient develops VFib arrest. What specific H&T reversible cause should be prioritized?", o: ["Hypothermia", "Hyperkalemia — dialysis patients frequently have dangerously elevated potassium that causes cardiac arrest; give IV calcium, bicarb, insulin/D50 during resuscitation", "Toxins only", "Hypovolemia"], a: 1, r: "Hyperkalemia is the most likely reversible cause in dialysis patients. IV calcium chloride (membrane stabilizer) during CPR, followed by K+-lowering agents. Address concurrent acidosis.", s: "Arrhythmias" },
  { q: "Post-ROSC from VFib, the client is hemodynamically unstable with MAP 55. What hemodynamic target should the nurse aim for?", o: ["MAP doesn't matter post-arrest", "Target MAP ≥65 mmHg with vasopressors/inotropes to maintain adequate cerebral and organ perfusion during TTM", "MAP >100 mmHg", "MAP 40-50 is acceptable"], a: 1, r: "Post-ROSC hemodynamic goals: MAP ≥65 mmHg (some target ≥80 for cerebral perfusion). Use norepinephrine/vasopressin for vasodilatory shock, dobutamine for cardiogenic component. Avoid hypotension.", s: "Arrhythmias" },
  { q: "A client in VFib arrest has received 3 shocks, epinephrine x2, and amiodarone 300 mg. VFib persists. What additional amiodarone dose is available?", o: ["No more can be given", "Amiodarone 150 mg can be given as a second dose for refractory VFib", "600 mg next dose", "Switch to vasopressin"], a: 1, r: "Amiodarone in cardiac arrest: first dose 300 mg, second dose 150 mg. After both doses, lidocaine 1-1.5 mg/kg is an alternative. Continue CPR and address H's and T's.", s: "Arrhythmias" },
  { q: "During TTM at 33°C post-VFib arrest, the client develops shivering. Why is this significant and how should it be managed?", o: ["Shivering is harmless", "Shivering increases metabolic demand and counteracts the neuroprotective benefit of cooling — treat with sedation (propofol, midazolam) and paralysis if needed", "Warm the patient", "Stop TTM"], a: 1, r: "Shivering increases oxygen consumption by 40-100%, counteracting TTM's neuroprotective benefit. Manage with sedation, skin counter-warming, magnesium, and paralysis (cisatracurium) if refractory.", s: "Arrhythmias" },
  { q: "A client is in VFib arrest. The only IV access is a foot IV. The nurse needs to give epinephrine. What is the best approach?", o: ["Give through foot IV with extra flush", "Establish IO access in the proximal tibia or humerus — faster and more reliable than peripheral IV for emergency drug delivery during arrest", "Wait for central line", "Give medication IM"], a: 1, r: "Distal peripheral IV is unreliable during arrest (minimal cardiac output for drug delivery). IO access (proximal tibia or humerus) is rapid to establish and provides reliable drug delivery comparable to central access.", s: "Arrhythmias" },
  { q: "Post-ROSC, the team is debating TTM target: 33°C vs 36°C. What does current evidence suggest?", o: ["Only 33°C is beneficial", "Both 33°C and 36°C show similar neurological outcomes — the key is maintaining any consistent target temperature and avoiding fever", "TTM has no benefit", "Only 36°C works"], a: 1, r: "TTM2 trial showed similar outcomes at 33°C and 36°C. Current guidelines recommend targeting 32-36°C. The critical factor is avoiding fever (>37.5°C), which worsens neurological outcomes. Choose a target and maintain it consistently.", s: "Arrhythmias" },
  { q: "A VFib arrest victim was found face-down in water 45 minutes ago. Body temperature is 28°C. After ROSC, the team considers terminating resuscitation due to prolonged arrest time. What principle applies?", o: ["Terminate — 45 minutes is too long", "No one is dead until warm and dead — hypothermia is neuroprotective and resuscitation should continue until the patient is rewarmed to at least 32°C", "Only continue for 30 more minutes", "It's always futile"], a: 1, r: "Hypothermia provides neuroprotection even during prolonged arrest. Cases of full neurological recovery after >60 minutes of CPR in hypothermic patients are documented. Continue resuscitation during active rewarming.", s: "Arrhythmias" },
  { q: "During a VFib arrest, ETCO2 suddenly increases from 15 to 45 mmHg. What does this most likely indicate?", o: ["Equipment malfunction", "ROSC — a sudden sustained rise in ETCO2 often indicates return of spontaneous circulation before a pulse is palpable", "Worsening arrest", "Need to increase ventilation rate"], a: 1, r: "Sudden sustained ETCO2 rise during CPR is often the earliest sign of ROSC — CO2 is being delivered to the lungs by restored circulation. Check for pulse. This sign may precede palpable pulse by seconds.", s: "Arrhythmias" },
  { q: "A client is successfully resuscitated from VFib arrest. An ICD is being considered. The client asks why they need a device when 'the doctors already fixed me.' What should the nurse explain?", o: ["You're right, you don't need it", "The ICD provides continuous monitoring and automatic treatment if VFib recurs — cardiac arrest survivors have a high recurrence rate without an ICD", "ICDs are only for research", "You can decide later"], a: 1, r: "Cardiac arrest survivors (secondary prevention) have significant VTach/VFib recurrence risk. ICD reduces mortality by automatically detecting and treating recurrences within seconds. This is the strongest ICD indication.", s: "Arrhythmias" },
  { q: "Post-ROSC from VFib arrest, the nurse notes the client's BP is 180/100 during TTM. Should this be treated?", o: ["No, hypertension is protective after arrest", "Yes — post-arrest hypertension increases risk of cerebral edema and should be managed to maintain MAP in the target range while avoiding hypotension", "Only treat if >200 systolic", "Stop all vasopressors only"], a: 1, r: "Post-ROSC blood pressure management: avoid both hypo- and hypertension. Severe hypertension can worsen cerebral edema after anoxic injury. Target MAP 65-100 mmHg. Use short-acting titratable agents.", s: "Arrhythmias" },

  // ===== HEART BLOCKS CAT (15 questions) =====
  { q: "A nurse encounters three clients with heart blocks:\n1. First-degree AV block, asymptomatic, HR 72\n2. Mobitz Type II with wide QRS, HR 38, lightheaded\n3. Wenckebach in an athlete, HR 58, asymptomatic\nPrioritize.", o: ["All need equal attention", "Client 2 — Mobitz II with symptoms and slow rate at high risk for complete block, needs immediate pacing preparation", "Client 1 first", "Client 3 first"], a: 1, r: "Mobitz II is infranodal, unpredictable, and high risk for sudden complete block. With symptoms and HR 38, needs immediate transcutaneous pacing preparation. First-degree and Wenckebach in athletes are benign.", s: "Arrhythmias" },
  { q: "A client with an anterior MI develops new RBBB + left anterior fascicular block (bifascicular block). What is the nurse's concern?", o: ["Benign finding in anterior MI", "Bifascicular block indicates extensive conduction system damage with risk of sudden complete heart block — apply transcutaneous pacing pads prophylactically", "Normal recovery pattern", "Only cosmetic concern"], a: 1, r: "New bifascicular block in anterior MI = widespread damage to the His-Purkinje system. Only the left posterior fascicle remains intact. If it fails, complete heart block occurs suddenly. Prophylactic TCP pads are essential.", s: "Arrhythmias" },
  { q: "A client with complete heart block and a ventricular escape rhythm of 28 bpm receives atropine 0.5 mg with no improvement. The nurse understands this is because:", o: ["The dose was too low", "Complete heart block is typically infranodal where parasympathetic innervation is absent — atropine only works on the AV node above the block", "Atropine always works for bradycardia", "The client is allergic to atropine"], a: 1, r: "Atropine blocks vagal tone at the AV node. In infranodal complete block, the tissue below the AV node lacks parasympathetic innervation, so atropine is ineffective. Pacing is required.", s: "Arrhythmias" },
  { q: "A post-VSD repair child develops progressive PR prolongation over 2 hours, advancing from 180 ms to 320 ms. What is the nurse's clinical concern?", o: ["Normal post-operative finding", "Progressive PR prolongation near the surgical site suggests evolving conduction system injury — may progress to complete heart block requiring pacing", "Wenckebach is always benign", "Equipment calibration issue"], a: 1, r: "In post-cardiac surgery, progressive PR prolongation indicates evolving conduction system injury (often from edema or suture near the AV node/His bundle). Close telemetry monitoring and pacing preparedness are essential.", s: "Arrhythmias" },
  { q: "A client has 2:1 AV block with HR 42 and narrow QRS. The nurse is unsure if this is Type I or Type II. What clinical features help distinguish?", o: ["Cannot distinguish", "Narrow QRS with 2:1 block suggests the block is at the AV node (more likely Type I). Response to atropine (improved conduction = AV nodal = Type I) can help differentiate", "Always Type II", "Always Type I"], a: 1, r: "Narrow QRS + 2:1 block favors AV nodal (Type I) level. Wide QRS favors infranodal (Type II). Atropine trial: improvement suggests AV nodal (Type I). No improvement = infranodal (Type II). Clinical distinction guides pacemaker decision.", s: "Arrhythmias" },
  { q: "A client with a new DDD pacemaker has a HR of 45 bpm. The pacemaker rate is set at 60 bpm. The nurse sees pacing spikes on the monitor but no corresponding QRS complexes. What is happening?", o: ["Normal pacemaker function", "Failure to capture — the pacemaker is firing but the electrical impulse is not depolarizing the myocardium", "Failure to sense", "Battery fully charged"], a: 1, r: "Pacing spikes without QRS = failure to capture. Rate below set minimum confirms the pacemaker isn't capturing. Causes: lead displacement, increased threshold, electrode issues. Increase mA output, reposition, notify provider.", s: "Arrhythmias" },
  { q: "A client with complete heart block has just had a transvenous pacemaker inserted. The nurse notes the client has hiccups synchronous with pacing spikes. What does this indicate?", o: ["Normal side effect", "The pacing lead may have perforated through the RV wall and is stimulating the diaphragm — this is a serious complication requiring immediate CXR and evaluation", "Anxiety response", "GI issue"], a: 1, r: "Diaphragmatic stimulation synchronized with pacing = possible RV perforation with lead stimulating the diaphragm. Requires urgent CXR, echo (pericardial effusion), and possible lead repositioning.", s: "Arrhythmias" },
  { q: "A nurse is performing transcutaneous pacing on a client with complete heart block. The mA output is at 80 mA and pacing spikes are visible, but no QRS complexes follow. What should the nurse do?", o: ["Maintain current settings", "Gradually increase the mA output until electrical capture is achieved (spike followed by wide QRS) — typical threshold is 50-100 mA but may be higher", "Decrease mA", "Switch to defibrillation"], a: 1, r: "If no capture at current mA, gradually increase output until each pacing spike is followed by a wide QRS and corresponding pulse. Some patients need higher output. Also verify pad placement (anterior-posterior optimal).", s: "Arrhythmias" },
  { q: "A client with a permanent pacemaker needs an MRI. The pacemaker was implanted 5 years ago. What must the nurse verify?", o: ["All pacemakers are MRI-safe", "Verify the pacemaker is MRI-conditional by checking the device ID card — older pacemakers may not be MRI-compatible and MRI could damage the device or cause lead heating", "MRI is always contraindicated", "No special precautions needed"], a: 1, r: "MRI-conditional pacemakers have specific labeling allowing MRI under certain conditions. Older devices may NOT be safe. Must verify: device model, lead compatibility, and program device to MRI mode before scan. Reprogram after.", s: "Arrhythmias" },
  { q: "An elderly client takes metoprolol, diltiazem, and digoxin. HR is 36 bpm. What is the nurse's analysis?", o: ["Need a pacemaker immediately", "The combination of THREE AV nodal blocking agents is the likely cause of excessive bradycardia — this is a medication-related cause that should be addressed before considering pacing", "All three medications are safe together", "Only stop one medication"], a: 1, r: "Triple AV nodal blockade (beta-blocker + non-DHP CCB + digoxin) is a common iatrogenic cause of severe bradycardia. Hold all three, assess response, check digoxin level and K+. Temporary pacing if unstable.", s: "Arrhythmias" },
  { q: "A client with Mobitz II is having a 'good day' — no symptoms and HR is 62 bpm with some native conduction. The client refuses a pacemaker saying 'I feel fine today.' How should the nurse respond?", o: ["If you feel fine, you don't need it", "Mobitz II is unpredictable — the conduction can fail suddenly without warning, causing syncope, cardiac arrest, or death. Feeling well today doesn't eliminate the risk", "Wait until symptoms occur", "Try medications instead"], a: 1, r: "Mobitz II is infranodal and can progress to complete block SUDDENLY without warning. Unlike Wenckebach (which gives gradual warning), Mobitz II can cause unexpected cardiac arrest. Pacemaker is indicated regardless of current symptoms.", s: "Arrhythmias" },
  { q: "A client with a temporary pacemaker is being transferred for a procedure. During transport, the pacemaker wire becomes partially dislodged. HR drops to 25 bpm. What is the MOST critical immediate action?", o: ["Push the wire back in", "Initiate transcutaneous pacing as backup while calling for help — do NOT manipulate the transvenous wire as this can cause arrhythmias or perforation", "Give atropine only", "Continue transport"], a: 1, r: "Dislodged transvenous pacer wire: DO NOT manipulate (risk of arrhythmia, perforation). Apply transcutaneous pacing immediately as bridge. Atropine can be tried but often fails in infranodal block. This is a pacemaker emergency.", s: "Arrhythmias" },
  { q: "A client with complete heart block has just received a permanent pacemaker. Post-procedure vitals: HR 72 (paced), BP 88/56 with JVD. CXR shows mediastinal widening. What complication should the nurse suspect?", o: ["Normal post-procedure findings", "Cardiac tamponade from lead perforation — hypotension, JVD, and mediastinal widening are classic signs requiring emergent pericardiocentesis", "Pneumothorax only", "Pacemaker malfunction"], a: 1, r: "Hypotension + JVD + mediastinal widening post-pacemaker insertion = cardiac tamponade (lead perforation with pericardial blood accumulation). Beck's triad: hypotension, JVD, muffled heart sounds. Emergent pericardiocentesis needed.", s: "Arrhythmias" },
  { q: "A nurse notes that a client's Wenckebach rhythm is occurring only during sleep, with normal conduction during the day. Is this a concern?", o: ["Very dangerous, needs pacemaker", "No — nocturnal Wenckebach from enhanced vagal tone during sleep is a physiologic finding, especially in young/athletic patients, and does NOT require treatment", "Always abnormal", "Needs immediate intervention"], a: 1, r: "Sleep-related Wenckebach from increased vagal tone is a benign physiologic phenomenon, particularly in young and athletic individuals. No treatment needed if asymptomatic and daytime conduction is normal.", s: "Arrhythmias" },
  { q: "A client with an inferior MI develops complete heart block with junctional escape at 45 bpm. The team is debating permanent pacemaker placement. What should the nurse understand about the prognosis?", o: ["Always needs permanent pacemaker", "Inferior MI with complete heart block is often TRANSIENT (resolves in days) because the RCA supplies the AV node — temporary pacing bridges until recovery", "Never recovers", "Ignore and observe"], a: 1, r: "Inferior MI affects the AV node (RCA supply). Complete block is usually reversible within 5-7 days as edema resolves. Temporary pacing (transcutaneous or transvenous) bridges until conduction recovers. Permanent pacemaker usually NOT needed.", s: "Arrhythmias" },

  // ===== SINUS BRADY/TACHY CAT (15 questions) =====
  { q: "Three clients with bradycardia:\n1. Post-op Day 1: HR 46, BP 86/52, confused, on metoprolol\n2. Collegiate athlete: HR 48, BP 120/72, running laps without symptoms\n3. Hypothyroid client: HR 54, BP 108/70, mild fatigue\nPrioritize.", o: ["All need atropine", "Client 1 — symptomatic drug-induced bradycardia with hemodynamic compromise requiring immediate atropine, hold metoprolol, consider glucagon", "Client 2 first", "Client 3 first"], a: 1, r: "Client 1: symptomatic bradycardia (hypotension, AMS) with identifiable cause (metoprolol). Immediate: atropine 0.5 mg IV, hold metoprolol, consider glucagon. Client 2: physiologic. Client 3: treat thyroid.", s: "Arrhythmias" },
  { q: "A postop client develops sinus tach HR 128, RR 28, BP 88/56, decreased UOP, and the wound drain has collected less than expected. What is the nurse's HIGHEST priority?", o: ["Administer a beta-blocker for rate control", "Assess for concealed hemorrhage — these findings suggest hypovolemia from bleeding; the tachycardia is compensatory and must NOT be suppressed with rate-controlling drugs", "Reassure the client", "Give anxiolytic"], a: 1, r: "Sinus tachycardia with hypotension + oliguria + low drain output in a postop patient = hemorrhage until proven otherwise. The tachycardia is maintaining cardiac output — suppressing it with beta-blockers could cause cardiovascular collapse.", s: "Arrhythmias" },
  { q: "A T4 spinal cord injury patient has HR 38, BP 72/44, warm and dry skin. The nurse suspects neurogenic shock. How does management differ from hypovolemic shock?", o: ["Identical management", "Neurogenic: atropine for bradycardia, vasopressors for vasodilation (warm/dry skin). Hypovolemic: IV fluid resuscitation (cool/clammy skin). Do not over-fluid neurogenic shock", "Only fluids for both", "Neither needs treatment"], a: 1, r: "Neurogenic shock: loss of sympathetic tone → bradycardia (atropine) + vasodilation (vasopressors). Warm, dry skin distinguishes from hypovolemic (cool, clammy). Excessive fluids can cause pulmonary edema without addressing vasodilation.", s: "Arrhythmias" },
  { q: "A nurse is triaging clients with sinus tachycardia. Which client has the MOST concerning underlying cause?\n1. HR 108 after morning coffee\n2. HR 118 with unilateral leg swelling, dyspnea, and pleuritic chest pain\n3. HR 112 during anxiety before a procedure\n4. HR 104 after mild exercise", o: ["Client 1 — caffeine sensitivity", "Client 2 — signs suggest pulmonary embolism, a life-threatening cause", "Client 3 — anxiety", "Client 4 — exercise"], a: 1, r: "Client 2: unilateral leg swelling (DVT) + dyspnea + pleuritic chest pain + tachycardia = PE until proven otherwise. Life-threatening emergency requiring immediate SpO2, CTA, and anticoagulation.", s: "Arrhythmias" },
  { q: "A client with beta-blocker overdose (metoprolol) has HR 28, BP 60/30. Atropine 3 mg total has been given without improvement. What specific antidote should the nurse prepare?", o: ["More atropine", "Glucagon 3-10 mg IV bolus — stimulates cardiac contractility through non-beta receptor mechanism, followed by epinephrine infusion if needed", "Flumazenil", "Naloxone"], a: 1, r: "Glucagon is the specific antidote for beta-blocker toxicity when atropine fails. It increases cAMP independently of beta receptors. High-dose insulin/euglycemia therapy is another option for refractory cases.", s: "Arrhythmias" },
  { q: "A client's sinus tachycardia is 140 bpm. The ER physician orders metoprolol IV 'to control the rate.' Lab shows Hgb 5.8 g/dL. What should the nurse do?", o: ["Administer the metoprolol as ordered", "Question the order — the tachycardia is compensatory for severe anemia. Suppressing it could cause cardiovascular collapse. The cause needs treatment (transfusion), not the rate", "Give diltiazem instead", "Add digoxin"], a: 1, r: "Critical nursing judgment: tachycardia with Hgb 5.8 is compensatory. The heart is racing to maintain O2 delivery with reduced carrying capacity. Beta-blocking this response could be fatal. Advocate for transfusion, not rate control.", s: "Arrhythmias" },
  { q: "A client on digoxin, furosemide, and carvedilol has HR 42 with nausea and visual changes (yellow-green halos). What is the most likely cause and what labs should the nurse prioritize?", o: ["Normal medication effects", "Digoxin toxicity potentiated by hypokalemia from furosemide — check STAT digoxin level and potassium immediately", "Carvedilol overdose", "Furosemide toxicity"], a: 1, r: "Classic digoxin toxicity triad: GI (nausea), visual (yellow-green halos), cardiac (bradycardia). Furosemide causes hypokalemia which potentiates digoxin toxicity. STAT dig level and K+ are critical.", s: "Arrhythmias" },
  { q: "A client with Cushing's triad (bradycardia, hypertension, irregular respirations) is developing progressively worsening bradycardia. What would be an error in management?", o: ["Treating the elevated ICP", "Giving atropine for the bradycardia without addressing the ICP — the bradycardia is a reflex response to critically elevated ICP; treating the symptom without the cause is dangerous", "Elevating the HOB", "Calling neurosurgery"], a: 1, r: "Cushing's triad bradycardia is a vagal reflex from brainstem compression. Treating with atropine without addressing ICP is futile and delays critical neurosurgical intervention. Treat the cause (ICP), not the symptom.", s: "Arrhythmias" },
  { q: "A client with sick sinus syndrome has tachy-brady syndrome: SVT at 180 bpm alternating with sinus pauses of 4 seconds. Why is medication management alone difficult?", o: ["Medications work well for both", "Rate-controlling drugs worsen the bradycardia; antiarrhythmic drugs may worsen pauses. A pacemaker is needed to treat the bradycardia so that rate-controlling medications can be safely used for the tachycardia", "Surgery is never needed", "Only treat the tachycardia"], a: 1, r: "Tachy-brady paradox: treating tachycardia (rate control) worsens bradycardia; treating bradycardia alone doesn't help tachycardia. Solution: pacemaker (prevents dangerous pauses) + rate control medications (safely treats tachycardia).", s: "Arrhythmias" },
  { q: "A client with CCB overdose (verapamil) has HR 34, BP 58/30. IV calcium and atropine have been given. What additional therapies should the nurse anticipate?", o: ["No further treatment available", "High-dose insulin with dextrose (insulin-euglycemia therapy), IV fluids, vasopressors, and potentially lipid emulsion therapy", "Only more calcium", "Dialysis"], a: 1, r: "Severe CCB toxicity management: IV calcium (ongoing), high-dose insulin/euglycemia (improves contractility by enhancing myocardial glucose uptake), vasopressors (norepinephrine), IV lipid emulsion, and possibly ECMO for refractory cases.", s: "Arrhythmias" },
  { q: "A nurse notes that a healthy 22-year-old in the ED for a minor laceration has a resting HR of 42 bpm. The client reports running marathons. What is the appropriate response?", o: ["Admit for pacemaker evaluation", "Document as physiologic athletic bradycardia — enhanced vagal tone and increased stroke volume cause resting bradycardia in well-conditioned athletes, no intervention needed", "Start atropine", "Order STAT cardiology consult"], a: 1, r: "Athletic bradycardia is the most common cause of resting HR <50 in young, healthy individuals. Enhanced parasympathetic tone + increased stroke volume = lower resting HR. Completely benign if asymptomatic.", s: "Arrhythmias" },
  { q: "A client with sinus tachycardia (HR 122) presents with weight loss, tremor, heat intolerance, and exophthalmos. What is the underlying cause and which lab confirms it?", o: ["Anxiety — check cortisol", "Hyperthyroidism (Graves' disease) — TSH will be very low with elevated T3/T4, causing the sinus tachycardia", "Dehydration — check BUN", "Pheochromocytoma — check catecholamines"], a: 1, r: "Classic hyperthyroidism: weight loss, tremor, heat intolerance, exophthalmos (Graves'), and tachycardia. TSH is suppressed (<0.01), T3/T4 elevated. Thyroid hormone increases cardiac sensitivity to catecholamines.", s: "Arrhythmias" },
  { q: "A nurse is caring for a septic client with HR 136 and MAP 55 despite IV fluid resuscitation. The provider orders esmolol 'to reduce cardiac demand.' What is the nurse's best response?", o: ["Administer as ordered", "Question the order — the tachycardia is a compensatory response to sepsis; suppressing it with beta-blockers in the setting of hypotension could worsen hemodynamic collapse", "Give at half dose", "Add diltiazem also"], a: 1, r: "In septic shock with hypotension, tachycardia maintains cardiac output. Beta-blocking this response can cause hemodynamic collapse. While some evidence supports careful esmolol use in SPECIFIC sepsis scenarios, it requires hemodynamic stability first (MAP ≥65).", s: "Arrhythmias" },
  { q: "A client in the ICU develops sudden bradycardia to 35 bpm during tracheal suctioning. What is the mechanism and what should the nurse do?", o: ["Equipment malfunction", "Vagal stimulation from suctioning triggered reflex bradycardia — stop suctioning immediately, hyperoxygenate, observe for spontaneous recovery; give atropine if persistent", "This never happens", "Increase suction pressure"], a: 1, r: "Tracheal suctioning stimulates the vagus nerve, causing reflex bradycardia. Prevention: pre-oxygenate, limit suction to 10-15 seconds. Treatment: stop suctioning, hyperoxygenate. Usually transient. Atropine if persistent/symptomatic.", s: "Arrhythmias" },
  { q: "A client with inappropriate sinus tachycardia (IST) has failed metoprolol and diltiazem. What medication should the nurse anticipate for IST specifically?", o: ["Amiodarone", "Ivabradine (Corlanor) — selectively blocks the funny (If) channel in the SA node, reducing HR without affecting BP or contractility", "Digoxin", "Adenosine"], a: 1, r: "Ivabradine is uniquely suited for IST: selectively reduces SA node firing rate via If channel blockade without affecting BP, contractility, or AV conduction. FDA-approved for HF but used off-label for IST.", s: "Arrhythmias" },

  // ===== CHD OVERVIEW CAT (15 questions) =====
  { q: "A newborn at 3 days of life develops sudden cardiovascular collapse with absent femoral pulses, metabolic acidosis, and gray mottled skin. What is the MOST likely diagnosis and immediate intervention?", o: ["Sepsis — start antibiotics", "Critical coarctation or ductal-dependent left heart lesion with ductal closure — start PGE1 IMMEDIATELY", "Pneumonia — start oxygen", "NEC — NPO and antibiotics"], a: 1, r: "Day 3 collapse + absent femoral pulses + acidosis = ductal closure in a ductal-dependent lesion (critical coarctation, HLHS, interrupted arch). PGE1 to reopen ductus is lifesaving. Airway/ventilation support simultaneously.", s: "Pediatrics" },
  { q: "A nurse is caring for a newborn on PGE1 for a ductal-dependent lesion. The infant develops periodic apnea requiring stimulation. What is the nurse's response?", o: ["Stop PGE1 immediately", "This is an expected side effect of PGE1 (10-12% incidence). Maintain PGE1, ensure intubation equipment at bedside, prepare for possible intubation if apnea worsens", "Give caffeine", "Decrease PGE1 rate"], a: 1, r: "Apnea is the most significant PGE1 side effect. PGE1 cannot be stopped (life-sustaining). Keep intubation supplies at bedside. If apnea becomes severe or frequent, elective intubation for airway protection.", s: "Pediatrics" },
  { q: "Parents of a baby with a large VSD ask why surgery can't wait until the child is older. What is the nurse's MOST important clinical explanation?", o: ["We can wait as long as needed", "Prolonged L→R shunting causes irreversible pulmonary vascular changes (Eisenmenger syndrome), making the defect inoperable if repair is delayed beyond the critical window", "Only cosmetic reasons for early repair", "Surgery is always elective"], a: 1, r: "Eisenmenger syndrome (irreversible pulmonary HTN with shunt reversal) develops from chronically increased pulmonary blood flow. Once established, VSD closure is CONTRAINDICATED. Early repair prevents this irreversible complication.", s: "Pediatrics" },
  { q: "A nurse performs CCHD screening on a newborn. Right hand SpO2 is 96%, right foot SpO2 is 82%. What does this >3% differential mean?", o: ["Normal finding", "Possible ductal-dependent left heart obstruction (e.g., coarctation) where postductal O2 is significantly lower than preductal — requires immediate echocardiography", "Equipment error", "Re-screen in 24 hours"], a: 1, r: "Pre-postductal gradient >3% suggests differential oxygenation: oxygenated blood from the LV reaches the right hand (preductal), but postductal lower body receives desaturated blood through the PDA from the RV. Classic for coarctation/HLHS.", s: "Pediatrics" },
  { q: "An infant with a moderate-large VSD is failing to thrive despite calorie-dense formula. The nurse notes persistent tachypnea, diaphoresis during feeds, and hepatomegaly. Medical management has been maximized. What does the nurse anticipate?", o: ["More dietary modifications", "Surgical VSD repair — failure of medical management (digoxin, furosemide, captopril) with ongoing HF and FTT is an indication for surgical intervention", "Higher calorie formula", "Feeding tube only"], a: 1, r: "When medical management fails to control HF and FTT in VSD: surgical repair is indicated. Continued medical therapy prolongs the child's suffering and risks irreversible pulmonary vascular changes. Surgery should not be delayed.", s: "Pediatrics" },
  { q: "A mother is told her baby has TGA and needs a balloon atrial septostomy. She asks why a 'hole in the heart' would help. What explanation is MOST accurate?", o: ["It's not a hole, it's a valve", "In TGA, the two circulations are parallel (not in series). Creating an atrial opening allows mixing of oxygenated and deoxygenated blood, improving oxygen delivery until definitive surgery", "It repairs the transposition", "It prevents strokes"], a: 1, r: "TGA: aorta from RV (deoxygenated) and PA from LV (oxygenated) = two parallel circuits. Without mixing, it's fatal. Septostomy creates communication for blood mixing until the arterial switch operation.", s: "Pediatrics" },
  { q: "A pediatric nurse is assessing four infants. Which finding is MOST suspicious for undiagnosed CHD?\n1. Infant who sweats during breastfeeding\n2. Infant with mild nasal congestion\n3. Infant who spits up after feeds\n4. Infant sleeping through the night", o: ["Infant 2 — congestion", "Infant 1 — diaphoresis during feeding is a classic sign of heart failure in infants with CHD", "Infant 3 — reflux", "Infant 4 — sleeping well"], a: 1, r: "Diaphoresis during feeding is a hallmark of infant HF from CHD. Feeding increases metabolic demand on an already stressed heart. Other signs: tachypnea, poor weight gain, prolonged feeds, hepatomegaly.", s: "Pediatrics" },
  { q: "A child with Fontan physiology (single ventricle) develops increasing edema, ascites, and protein-losing enteropathy. What is happening?", o: ["Normal Fontan physiology", "Fontan circulation failure — elevated central venous pressures cause hepatic congestion, lymphatic dysfunction, and intestinal protein loss, a serious long-term Fontan complication", "Kidney disease", "Allergic reaction"], a: 1, r: "Fontan failure: the single ventricle cannot maintain adequate output against elevated systemic venous pressures. PLE, ascites, and edema indicate failing Fontan physiology. May need optimization or consideration of heart transplant.", s: "Pediatrics" },
  { q: "A nurse is counseling parents about their child's small muscular VSD. The cardiologist said 'it may close on its own.' What additional teaching is MOST important?", o: ["It will definitely close", "Up to 80% of small muscular VSDs close spontaneously by age 2-3. Follow-up echocardiograms will monitor progress. Report new symptoms: poor feeding, breathing fast, sweating during feeds", "No follow-up needed", "Surgery is inevitable"], a: 1, r: "Realistic counseling: high spontaneous closure rate for small muscular VSDs, but monitoring is essential. Parents must watch for HF symptoms that would indicate the VSD is hemodynamically significant.", s: "Pediatrics" },
  { q: "A child with an unrepaired ASD has been asymptomatic for 10 years. Recent echo shows Qp:Qs of 2.2:1 with RV dilation. What does the nurse anticipate?", o: ["Continue observation", "ASD closure is recommended — significant shunt (>1.5:1) with RV dilation warrants intervention to prevent arrhythmias, paradoxical embolism, and progressive RV dysfunction", "Start medications", "No intervention ever needed"], a: 1, r: "Hemodynamically significant ASD (Qp:Qs >1.5:1 with RV dilation) should be closed to prevent long-term complications even if asymptomatic. Secundum ASD may be amenable to device closure; others need surgery.", s: "Pediatrics" },
  { q: "A newborn fails the CCHD screening (SpO2 91% in right hand, 90% in foot). The pulse oximetry screening protocol says to rescreen in one hour. The nurse notices the baby looks dusky. What should the nurse do?", o: ["Wait and rescreen as protocol directs", "Do not delay — a cyanotic-appearing newborn with SpO2 <95% needs immediate clinical evaluation and echocardiography regardless of the rescreening protocol", "Rescreen in 24 hours", "Discharge with outpatient follow-up"], a: 1, r: "While the protocol allows rescreening, clinical judgment supersedes protocol when the baby appears cyanotic. Visible duskiness + low SpO2 = immediate evaluation needed. Don't delay clinical assessment for protocol compliance.", s: "Pediatrics" },
  { q: "A neonate diagnosed with HLHS (hypoplastic left heart syndrome) needs surgical palliation. The parents ask about the Norwood procedure. What is the nurse's understanding?", o: ["It's a simple procedure with low risk", "The Norwood is the first of three staged palliative surgeries (Norwood → Glenn → Fontan) that reconfigure the heart for single-ventricle physiology; it is high-risk with significant mortality", "It fixes the left ventricle", "It's optional"], a: 1, r: "HLHS requires staged surgical palliation: Norwood (neonatal, highest risk ~15-20% mortality), Glenn (~6 months), Fontan (~2-4 years). Creates single-ventricle physiology. Alternative: heart transplant. Without surgery, HLHS is fatal.", s: "Pediatrics" },
  { q: "A nurse is caring for a post-Fontan patient who develops acute cyanosis. What should the nurse understand about Fontan physiology that explains this?", o: ["Fontan patients don't get cyanotic", "In Fontan circulation, systemic venous return goes passively to the lungs. Any decrease in venous return (dehydration, hypovolemia) or increase in pulmonary pressures reduces pulmonary blood flow and causes cyanosis", "Cyanosis means the Fontan has failed", "This is normal"], a: 1, r: "Fontan physiology depends on passive venous flow to lungs. Anything reducing preload (dehydration) or increasing pulmonary resistance (respiratory infection, PE) decreases pulmonary flow → cyanosis. Maintain hydration and prevent respiratory illness.", s: "Pediatrics" },
  { q: "A child with polycythemia from cyanotic CHD (Hct 68%) is at risk for what complication?", o: ["Anemia", "Stroke from increased blood viscosity — polycythemia with Hct >65% significantly increases thrombosis risk requiring potential phlebotomy", "Bleeding only", "No complications"], a: 1, r: "Hct >65% from compensatory polycythemia increases blood viscosity → stroke, thrombosis risk. May need partial exchange transfusion/phlebotomy. Also causes headaches, dizziness, and exercise intolerance.", s: "Pediatrics" },
  { q: "A nurse is reviewing medications for an infant with HF from a large VSD. The infant is on digoxin, furosemide, and captopril. Before giving digoxin, what is the MOST critical assessment?", o: ["Blood pressure only", "Apical pulse for one full minute (hold if <100 bpm in infants) AND verify potassium is within normal range (furosemide depletes K+, increasing digoxin toxicity risk)", "Temperature", "Respiratory rate only"], a: 1, r: "Two critical assessments before infant digoxin: (1) apical pulse for 1 full minute — hold if <100 bpm (infants). (2) Check potassium — furosemide causes hypokalemia which dramatically increases digoxin toxicity risk.", s: "Pediatrics" },

  // ===== TETRALOGY OF FALLOT CAT (15 questions) =====
  { q: "An infant with unrepaired TOF becomes deeply cyanotic, inconsolable, and hyperpneic during a blood draw. The nurse places the infant in knee-chest position and calms the infant. SpO2 remains 55%. What is the next intervention?", o: ["Continue knee-chest only", "Administer IV morphine 0.1 mg/kg to relax infundibular spasm, supplemental O2, and prepare IV phenylephrine if no improvement", "Cardioversion", "Intubation immediately"], a: 1, r: "Tet spell management escalation: (1) Knee-chest + calm (done). (2) O2. (3) IV morphine (relaxes infundibular spasm, reduces catecholamines). (4) IV phenylephrine if persistent (increases SVR). (5) Consider IV propranolol or surgery.", s: "Pediatrics" },
  { q: "A child with TOF has scheduled blood draws weekly. The nurse notices each blood draw triggers significant agitation and mild cyanosis. What preventive measure should the nurse implement?", o: ["No changes possible", "Apply EMLA cream before draws, allow parental presence for comfort, cluster labs to reduce frequency, and have knee-chest position supplies and emergency medications ready", "Sedate for all draws", "Cancel all labs"], a: 1, r: "Preventing tet spells: minimize agitation triggers. EMLA cream reduces pain, parental comfort reduces crying, clustering reduces procedures. Always have emergency supplies ready (O2, morphine, phenylephrine).", s: "Pediatrics" },
  { q: "A parent asks why their TOF child turns blue when crying but their neighbor's VSD baby does not. What physiologic explanation is MOST accurate?", o: ["All heart defects cause cyanosis", "TOF has R→L shunting through the VSD (deoxygenated blood enters systemic circulation) due to RVOT obstruction. VSD has L→R shunting (oxygenated blood recirculates to lungs) with no cyanosis initially", "The VSD child will turn blue later", "It depends on the child's weight"], a: 1, r: "TOF: RVOT obstruction forces deoxygenated blood R→L through VSD into aorta → cyanosis. VSD alone: higher LV pressure pushes blood L→R back to lungs (no deoxygenated blood enters systemic circulation → no cyanosis).", s: "Pediatrics" },
  { q: "A neonate with severe TOF (near-pulmonary atresia) requires PGE1 to maintain ductal patency for pulmonary blood flow. What surgical palliation should the nurse anticipate?", o: ["Immediate complete repair", "Modified BT shunt — subclavian-to-PA graft to provide pulmonary blood flow until the child is large enough for complete repair", "Fontan procedure", "Heart transplant"], a: 1, r: "Ductal-dependent TOF (severe RVOT obstruction or pulmonary atresia): PGE1 maintains pulmonary flow via PDA. BT shunt creates a surgical alternative blood supply to lungs. Complete repair when older/larger.", s: "Pediatrics" },
  { q: "Post-TOF repair, a child develops junctional ectopic tachycardia (JET) with HR 200 and hemodynamic compromise. What should the nurse understand about this specific arrhythmia?", o: ["Common benign finding", "JET is the most common arrhythmia after TOF repair, originating from the conduction system area disrupted during VSD closure. Treatment: cooling, reduce catecholamines, IV amiodarone", "VTach", "Equipment artifact"], a: 1, r: "JET is common post-TOF repair: automatic tachycardia from irritated junctional tissue near the VSD patch. Treatment: mild hypothermia (cooling blanket), reduce inotropes/catecholamines, IV amiodarone. Usually self-resolves in days.", s: "Pediatrics" },
  { q: "A teenager who had TOF repair at 6 months now has severe pulmonary regurgitation with RV dilation on echo. They are asymptomatic but exercise testing shows decreased capacity. What does the nurse anticipate?", o: ["No intervention — they're asymptomatic", "Pulmonary valve replacement — progressive RV dilation with declining exercise capacity indicates timing for intervention to preserve RV function before irreversible damage", "Heart transplant", "Medication only"], a: 1, r: "Timing of PVR after TOF repair is critical: too early = unnecessary surgery, too late = irreversible RV damage. Progressive RV dilation + declining exercise capacity = optimal timing window even without resting symptoms.", s: "Pediatrics" },
  { q: "During a tet spell, the nurse notes the systolic murmur at the left upper sternal border has DISAPPEARED. What does this mean?", o: ["The child is getting better", "Worsening — the murmur disappears because virtually NO blood is flowing through the RVOT. This indicates severe infundibular spasm with near-total R→L shunting", "The VSD closed", "Equipment malfunction"], a: 1, r: "Paradox: murmur disappearance during tet spell is OMINOUS. The murmur is from blood flowing through the RVOT obstruction. No murmur = no flow through RVOT = nearly all blood shunting R→L. Escalate treatment immediately.", s: "Pediatrics" },
  { q: "A nurse is teaching parents of an infant with unrepaired TOF about iron supplementation. The parents ask why iron is important when 'the baby already has too many red blood cells.' What is the best explanation?", o: ["Iron is not needed with polycythemia", "Even with elevated RBC count, iron deficiency makes RBCs rigid and less deformable, worsening blood flow and potentially triggering tet spells. Iron maintains RBC quality, not just quantity", "Iron will increase RBCs further", "Only give iron after surgery"], a: 1, r: "Iron-deficient RBCs are rigid and poorly deformable, worsening microvascular flow. In cyanotic CHD, iron deficiency can trigger tet spells by increasing blood viscosity despite adequate hemoglobin. Quality of RBCs matters.", s: "Pediatrics" },
  { q: "A child with repaired TOF develops exercise-induced sustained VTach at age 15. What long-term complication of TOF repair does this represent?", o: ["Unrelated to TOF", "Late arrhythmia risk — scar tissue from VSD patch and RV incision creates substrate for reentrant VTach. May require ICD placement for secondary prevention", "Normal adolescent finding", "Medication side effect"], a: 1, r: "Late VTach after TOF repair: reentry circuits around surgical scars (VSD patch, ventriculotomy). Significant cause of sudden death in adults with repaired TOF. Requires ICD and possibly catheter ablation. Lifelong risk.", s: "Pediatrics" },
  { q: "An unrepaired TOF infant's baseline SpO2 is typically 78-82%. During a well-check visit, the SpO2 is 72%. The infant appears comfortable. Should the nurse be concerned?", o: ["No — this is within the expected range", "Yes — a drop of >5% from baseline is significant even if the infant appears well. Assess for dehydration, infection, anemia, or progressive RVOT obstruction", "Only concerned if <50%", "This is normal variation"], a: 1, r: "In cyanotic CHD, the individual baseline is the reference point, not normal values. A sustained drop >5% from baseline warrants investigation even without symptoms. Dehydration, illness, or progressive obstruction may be the cause.", s: "Pediatrics" },
  { q: "A mother notices her 3-month-old with TOF becomes most cyanotic first thing in the morning after sleeping. What is the likely explanation?", o: ["Sleep apnea", "Morning dehydration from overnight fasting concentrates blood, increasing viscosity, and positional changes upon waking can trigger infundibular spasm", "Night terrors", "Normal finding in all infants"], a: 1, r: "Overnight dehydration (no feeds) increases blood viscosity (especially with polycythemia). Additionally, catecholamine surge upon waking and position changes can trigger infundibular spasm. Ensure adequate overnight hydration.", s: "Pediatrics" },
  { q: "A nurse is preparing an infant with TOF for complete repair. Which pre-operative assessments are MOST critical?", o: ["Only weight", "Detailed echocardiography for pulmonary artery anatomy, hemoglobin/hematocrit for polycythemia, hydration status, and current iron studies", "Only blood type", "Only chest X-ray"], a: 1, r: "Pre-op TOF assessment: echo (PA anatomy guides surgical approach), Hgb/Hct (excessive polycythemia increases surgical bleeding risk — may need partial exchange), hydration (dehydration worsens viscosity), iron (deficiency worsens RBC rigidity).", s: "Pediatrics" },
  { q: "Post-TOF repair, the child has complete heart block requiring temporary pacing for 5 days, then spontaneous conduction returns. Does this child still need a permanent pacemaker?", o: ["Yes, always after transient block", "Usually not — transient complete heart block from post-operative edema often resolves. However, the child needs lifelong monitoring as delayed conduction disease can develop years later", "Never needs monitoring", "Immediate permanent pacemaker"], a: 1, r: "Transient post-surgical heart block (resolving within 7-10 days) usually doesn't need permanent pacemaker. However, these patients have higher lifetime risk of conduction disease and need lifelong monitoring.", s: "Pediatrics" },
  { q: "A school-age child with repaired TOF is cleared for sports but the family is anxious. What specific guidance should the nurse provide?", o: ["No restrictions at all", "Most repaired TOF children can participate in moderate-intensity sports. Specific restrictions depend on residual findings (PR severity, RV function, arrhythmia risk). Activity guidelines come from cardiology evaluation", "Avoid all sports", "Only swimming"], a: 1, r: "Activity advice must be individualized based on current cardiac status: residual PR severity, RV function, exercise testing results, and arrhythmia risk. Most well-repaired TOF patients tolerate moderate activity well.", s: "Pediatrics" },
  { q: "An adult with repaired TOF is 28 weeks pregnant. What specific cardiac concerns should the obstetric nurse monitor?", o: ["No cardiac concerns", "Pregnancy increases blood volume by 40-50%, which stresses the RV already compromised by chronic PR — monitor for arrhythmias, RV dysfunction, and heart failure", "Only monitor fetal heart", "Routine pregnancy care only"], a: 1, r: "Pregnancy's hemodynamic changes (increased blood volume, decreased SVR, increased CO) stress the already-compromised RV. Monitor for: arrhythmias, RV failure symptoms, and progressive PR. Multidisciplinary cardio-obstetric care essential.", s: "Pediatrics" },

  // ===== SEPTAL DEFECTS (VSD/ASD) CAT (15 questions) =====
  { q: "A nurse is caring for two infants with septal defects:\n1. Infant with small muscular VSD: loud murmur, gaining weight well, no respiratory distress\n2. Infant with large perimembranous VSD: diaphoresis during feeds, FTT, tachypnea, hepatomegaly\nWhich infant needs surgical referral?", o: ["Both need immediate surgery", "Infant 2 — signs of heart failure from hemodynamically significant VSD despite medical management indicate need for surgical repair", "Infant 1 — louder murmur is more dangerous", "Neither — all VSDs close on their own"], a: 1, r: "Small restrictive VSDs (loud murmur, asymptomatic) often close spontaneously. Large nonrestrictive VSDs causing HF and FTT despite medical management need surgical repair to prevent Eisenmenger syndrome.", s: "Pediatrics" },
  { q: "A child with a previously well-tolerated VSD is now developing clubbing and progressive cyanosis. The murmur has become quieter. What serious complication has developed?", o: ["The VSD is closing", "Eisenmenger syndrome — irreversible pulmonary HTN has caused shunt reversal from L→R to R→L, making surgical closure contraindicated", "Pneumonia", "The murmur equipment is broken"], a: 1, r: "Eisenmenger: chronically elevated pulmonary flow → irreversible pulmonary HTN → shunt reversal (R→L) → cyanosis. Quieter murmur reflects equalized pressures. Surgical closure now CONTRAINDICATED (would remove the only pressure relief valve for the RV).", s: "Pediatrics" },
  { q: "An adult patient with a known ASD presents with new-onset palpitations and an irregular pulse. Echo shows significant RA dilation. What is the MOST likely rhythm disturbance?", o: ["Ventricular tachycardia", "Atrial fibrillation or flutter from chronic right atrial volume overload and dilation", "Sinus bradycardia", "Complete heart block"], a: 1, r: "Unrepaired ASD → chronic RA volume overload → atrial stretch and dilation → substrate for atrial arrhythmias. This is why guidelines recommend ASD closure in childhood to prevent these long-term complications.", s: "Pediatrics" },
  { q: "A child is scheduled for transcatheter ASD device closure. The parents ask about the advantages over open-heart surgery. What should the nurse explain?", o: ["No advantages — surgery is always better", "Device closure avoids sternotomy and cardiopulmonary bypass, has shorter recovery, and lower complication rates for secundum ASDs. However, not all ASD types are amenable to device closure", "Device closure works for all ASDs", "It's experimental"], a: 1, r: "Transcatheter device closure (Amplatzer) is preferred for secundum ASDs with adequate rims. Advantages: no CPB, no sternotomy, 1-2 day hospital stay, faster recovery. Primum and sinus venosus ASDs require surgical repair.", s: "Pediatrics" },
  { q: "Post-VSD repair, a child develops sudden bradycardia with a ventricular rate of 35 bpm and AV dissociation on telemetry. What complication has occurred?", o: ["Normal post-operative finding", "Complete heart block from injury to the AV node/bundle of His during VSD patch placement — requires immediate pacing", "Medication side effect", "Lead displacement"], a: 1, r: "The AV node and bundle of His course along the posteroinferior rim of membranous VSDs. Surgical repair risks direct injury. Complete heart block requiring permanent pacemaker occurs in 1-2% of cases.", s: "Pediatrics" },
  { q: "A nurse is counseling parents of a neonate with a moderate VSD. What is the MOST important long-term concern the nurse should discuss?", o: ["The child can never exercise", "If the VSD doesn't close or shrink, prolonged L→R shunting can cause irreversible pulmonary vascular disease (Eisenmenger), making the defect inoperable — timely follow-up is critical", "VSDs always need surgery", "No long-term concerns exist"], a: 1, r: "The critical message: timing matters. Regular follow-up monitors for signs of hemodynamic significance. If HF or pulmonary HTN develops, surgical repair must occur BEFORE irreversible vascular changes (typically before age 1-2 for large VSDs).", s: "Pediatrics" },
  { q: "An infant with VSD on digoxin, furosemide, and captopril has today's potassium at 3.0 mEq/L. What is the nurse's priority concern?", o: ["Potassium is within normal range", "Hypokalemia from furosemide potentiates digoxin toxicity — critical to replace potassium and monitor for signs of digoxin toxicity (bradycardia, vomiting, arrhythmias)", "Only recheck in a week", "Increase furosemide dose"], a: 1, r: "Hypokalemia + digoxin = dangerous combination. Low K+ enhances digoxin binding to the Na/K ATPase pump, increasing toxicity risk. Replace K+ urgently, check digoxin level, hold digoxin if bradycardic.", s: "Pediatrics" },
  { q: "A 35-year-old with an unrepaired ASD has a cryptogenic stroke. Workup reveals a PFO with right-to-left shunting. What mechanism caused the stroke?", o: ["Atherosclerotic disease", "Paradoxical embolism — a venous thrombus crossed through the PFO into systemic arterial circulation", "Hemorrhagic stroke", "Atrial fibrillation"], a: 1, r: "Paradoxical embolism: venous thrombus (often DVT) crosses the atrial septal defect/PFO during transient R→L shunting (coughing, Valsalva) → enters systemic circulation → stroke. PFO closure may be recommended after cryptogenic stroke.", s: "Pediatrics" },
  { q: "A nurse is assessing an infant with ASD. The most reliable auscultatory finding is:", o: ["Harsh holosystolic murmur at LLSB", "Fixed splitting of S2 that does not vary with respiration — pathognomonic for ASD", "Continuous machinery murmur", "No murmur can be heard"], a: 1, r: "Fixed S2 splitting is the hallmark of ASD. The ASD equalizes atrial pressures, maintaining constant RV volume regardless of respiratory phase. In normal hearts, S2 splitting varies with inspiration/expiration.", s: "Pediatrics" },
  { q: "Two VSD patients are being compared:\n1. Infant with small VSD: extremely loud harsh murmur, growing well, no respiratory symptoms\n2. Infant with large VSD: very soft murmur, FTT, tachypnea, hepatomegaly\nWhat explains this paradox?", o: ["Louder murmur = worse disease", "Small restrictive VSDs produce louder murmurs (high velocity through small opening). Large nonrestrictive VSDs have quieter murmurs (less pressure gradient) but are hemodynamically MORE significant", "Both murmurs indicate same severity", "Equipment calibration issue"], a: 1, r: "VSD murmur paradox: small hole + high pressure gradient = loud murmur. Large hole + equalized pressures = soft murmur but massive shunt volume. Clinical assessment (growth, symptoms) matters more than murmur intensity.", s: "Pediatrics" },
  { q: "A child with a large VSD develops Eisenmenger syndrome. The family asks about heart-lung transplant. What should the nurse understand?", o: ["Heart-lung transplant cures everything", "Heart-lung or lung transplant with VSD repair is the only surgical option once Eisenmenger develops. The original VSD closure alone is contraindicated because the RV needs the VSD as a pressure relief valve", "Simple VSD patch repair", "No options available"], a: 1, r: "Once Eisenmenger develops: VSD closure alone = RV failure (loses pressure pop-off). Options: heart-lung transplant, single/double lung transplant with VSD repair, or medical management (pulmonary vasodilators). Prognosis is guarded.", s: "Pediatrics" },
  { q: "Post-transcatheter ASD device closure, the nurse notes the child has developed a new high-grade fever at 48 hours with positive blood cultures. What complication should be suspected?", o: ["Routine postoperative fever", "Device-related endocarditis — the foreign body provides a nidus for bacterial adherence before endothelialization is complete", "URI", "Normal response"], a: 1, r: "Device endocarditis is a rare but serious complication. The device is a foreign body until fully endothelialized (6 months). SBE prophylaxis is recommended for dental procedures during this period. Blood cultures and IV antibiotics are critical.", s: "Pediatrics" },
  { q: "An infant with VSD is struggling to gain weight despite concentrated formula. The nurse's feeding assessment reveals the infant takes only 1 oz over 45 minutes before falling asleep exhausted. What modification should the nurse suggest?", o: ["Force the infant to eat more", "NG tube supplementation to reduce feeding workload while maintaining adequate caloric intake — feeding is the 'exercise test' for these infants", "Switch to regular formula", "Stop all oral feeds"], a: 1, r: "Feeding is an infant's 'exercise' — excessive metabolic demand from HF makes oral feeding exhausting. NG/OG supplementation provides calories without the energy expenditure. Continue some oral feeds to maintain skills.", s: "Pediatrics" },
  { q: "A nurse is monitoring a child post-surgical VSD repair. The telemetry shows new PR prolongation (240 ms) that was not present pre-operatively. What is the significance?", o: ["Normal post-anesthesia finding", "New first-degree AV block from surgical proximity to the conduction system — monitor closely for progression to higher-degree block which may require pacing", "Equipment artifact", "No significance"], a: 1, r: "New conduction abnormality post-VSD repair indicates potential conduction system injury. First-degree block may be from edema (transient) or direct injury (permanent). Monitor for progression — complete heart block can develop hours to days later.", s: "Pediatrics" },
  { q: "A teenage patient with repaired ASD asks about future pregnancy risk. What should the nurse communicate?", o: ["No pregnancy-related risks", "Repaired ASD with no residual defect generally carries low pregnancy risk, but pre-pregnancy cardiac assessment is recommended. Unrepaired ASD with significant shunt has higher risks from volume changes of pregnancy", "Pregnancy is contraindicated after ASD repair", "Only C-section is safe"], a: 1, r: "Well-repaired ASD (no residual shunt, normal RV function): pregnancy generally well-tolerated. Pre-pregnancy cardiology evaluation recommended. Unrepaired significant ASD: increased arrhythmia risk from pregnancy's 40-50% blood volume increase.", s: "Pediatrics" },

  // ===== COARCTATION OF THE AORTA CAT (15 questions) =====
  { q: "A 3-day-old neonate presents with acute cardiovascular collapse: absent femoral pulses, metabolic acidosis, mottled gray skin, and hepatomegaly. What is the MOST critical immediate intervention?", o: ["IV antibiotics for sepsis", "Start PGE1 immediately to reopen the ductus arteriosus — this presentation is classic for critical coarctation with ductal closure", "Oxygen and observation", "Echocardiography before any treatment"], a: 1, r: "Critical coarctation: ductal closure removes the only pathway for blood flow to the lower body. PGE1 reopens the ductus within minutes, restoring perfusion. Every minute of delay worsens acidosis and organ damage. Do not wait for echo.", s: "Pediatrics" },
  { q: "A nurse performs the newborn cardiovascular assessment and finds bounding brachial pulses with weak femoral pulses and a BP gradient of 28 mmHg (arms > legs). What diagnosis does this suggest?", o: ["Normal neonatal finding", "Coarctation of the aorta — upper-lower extremity BP gradient >20 mmHg with diminished femoral pulses is the hallmark finding", "PDA", "VSD"], a: 1, r: "Coarctation triad: (1) Upper extremity hypertension, (2) Weak/absent femoral pulses, (3) >20 mmHg systolic BP gradient upper > lower extremities. This assessment should be performed on every newborn.", s: "Pediatrics" },
  { q: "A child with repaired coarctation develops paradoxical hypertension and severe abdominal pain 2 days post-operatively. What complication has occurred?", o: ["Recoarctation", "Post-coarctectomy syndrome — sudden increased mesenteric blood flow causes mesenteric arteritis with hypertension and abdominal pain", "Appendicitis", "Surgical site infection"], a: 1, r: "Post-coarctectomy syndrome: mesenteric arteries suddenly exposed to pulsatile flow after repair → arteritis → abdominal pain, nausea, hypertension. Treatment: antihypertensives (nitroprusside, esmolol) and bowel rest. Usually resolves in days.", s: "Pediatrics" },
  { q: "A teenager with undiagnosed coarctation presents with nosebleeds, headaches during exercise, and calf pain during running. What clinical reasoning connects these symptoms?", o: ["These are unrelated complaints", "Upper body HTN (headaches, epistaxis) and lower body hypoperfusion (calf claudication) from aortic narrowing — classic undiagnosed coarctation triad in older children", "Migraine and growing pains", "Drug abuse"], a: 1, r: "Undiagnosed coarctation: upper body receives high-pressure flow (HTN → headaches, epistaxis), lower body receives reduced flow (exercise claudication, weak pulses). Often diagnosed when HTN is investigated in adolescence.", s: "Pediatrics" },
  { q: "A neonate on PGE1 for critical coarctation needs stabilization before surgery. The nurse notes apneic episodes. What is the priority nursing action?", o: ["Stop PGE1 — it's causing the apnea", "Maintain PGE1 (life-sustaining), ensure intubation equipment at bedside, prepare for elective intubation if apnea worsens — PGE1 cannot be discontinued", "Give caffeine", "Reduce PGE1 to subtherapeutic dose"], a: 1, r: "PGE1 apnea dilemma: apnea occurs in 10-12% but PGE1 CANNOT be stopped (ductal closure = death). Management: airway preparedness, intubation if apnea is frequent/prolonged. Continue PGE1 at effective dose until surgery.", s: "Pediatrics" },
  { q: "A 14-year-old diagnosed with coarctation is being evaluated for repair. What is the preferred treatment approach at this age?", o: ["Open surgical repair only", "Transcatheter balloon angioplasty with stent placement — less invasive with shorter recovery, preferred for native coarctation in older children/adolescents of adequate size", "Medication management only", "No treatment needed at this age"], a: 1, r: "For older children (>25 kg)/adolescents: transcatheter stent placement is increasingly preferred. Less invasive, shorter recovery, avoidable thoracotomy. Surgery reserved for complex anatomy or very young infants.", s: "Pediatrics" },
  { q: "After coarctation repair at age 6 months, a child's BP at age 5 is consistently 130/85 despite no residual gradient on echo. What does the nurse understand?", o: ["The repair failed", "Persistent HTN occurs in up to 30% of repaired coarctation patients, likely from RAAS activation and vascular remodeling during the coarctation period — lifelong BP monitoring is required", "Normal childhood BP", "Equipment error"], a: 1, r: "Late HTN is the most common long-term complication: RAAS upregulation from prior renal hypoperfusion, abnormal baroreceptor function, and altered aortic compliance persist even after successful repair. Antihypertensives often needed lifelong.", s: "Pediatrics" },
  { q: "A nurse is performing CCHD screening on a newborn. SpO2 is 98% in the right hand and 94% in the right foot. How does the nurse interpret this?", o: ["Normal — both are above 95%", "FAILED — >3% difference between pre- and postductal saturations suggests differential oxygenation from a ductal-dependent left-sided lesion such as coarctation", "Only look at the hand reading", "Rescreen in 1 week"], a: 1, r: ">3% difference between preductal (right hand) and postductal (foot) = failed screen. In coarctation, oxygenated blood from LV reaches right arm (preductal), but desaturated blood from PDA reaches lower body (postductal).", s: "Pediatrics" },
  { q: "A child with Turner syndrome (45,X) is being evaluated. What cardiac screening is essential?", o: ["No cardiac screening needed", "Echocardiography for coarctation (10-15% incidence) and bicuspid aortic valve (30% incidence) — both are strongly associated with Turner syndrome", "Only check for ASD", "Only blood tests"], a: 1, r: "Turner syndrome cardiac associations: coarctation (10-15%), BAV (30%), aortic dilation/dissection risk. All Turner patients need baseline echo with follow-up imaging throughout life, especially monitoring aortic dimensions.", s: "Pediatrics" },
  { q: "A nurse is assessing an infant post-subclavian flap aortoplasty for coarctation repair. What long-term effect of this specific surgical technique should the nurse monitor for?", o: ["No specific effects", "Left arm BP may be permanently lower than right arm because the left subclavian artery was sacrificed for the repair — always use right arm for future BP measurements", "Right arm will be affected", "Both arms are identical"], a: 1, r: "Subclavian flap repair uses the left subclavian artery, potentially causing: lower left arm BP, left arm shortening, and reduced left arm perfusion during exercise. Use RIGHT arm for all future BP monitoring.", s: "Pediatrics" },
  { q: "A client with repaired coarctation at age 2 is now 25 years old. MRI shows a 4.5 cm aortic aneurysm at the repair site. What does this finding require?", o: ["Annual monitoring only", "Surgical or endovascular intervention — aortic aneurysm at the repair site is a known late complication with rupture risk requiring elective intervention", "No action — this is expected", "Only recheck in 5 years"], a: 1, r: "Late aortic aneurysm at the coarctation repair site is a serious long-term complication. Can occur decades after repair. Risk of rupture/dissection requires intervention. This is why lifelong imaging surveillance is mandatory.", s: "Pediatrics" },
  { q: "Two neonates present with shock:\n1. Neonate with absent femoral pulses, acidosis, gray mottled skin\n2. Neonate with equal pulses, fever, irritability, poor feeding\nWhat distinguishes these presentations?", o: ["Both are sepsis", "Neonate 1: critical coarctation (differential perfusion) — start PGE1. Neonate 2: more consistent with sepsis (equal pulses with systemic infection signs) — start antibiotics. Both need resuscitation", "Both are coarctation", "Neither needs treatment"], a: 1, r: "Key distinguishing feature: DIFFERENTIAL perfusion (absent femoral pulses) = coarctation. EQUAL pulses with systemic illness signs = more likely sepsis. However, both can coexist and both need aggressive resuscitation. PGE1 for suspected coarctation is low-risk and potentially lifesaving.", s: "Pediatrics" },
  { q: "Why do some neonates with coarctation present well at birth but collapse at day 3-5?", o: ["Birth defects worsen over time", "The PDA maintains lower body perfusion at birth. When the ductus naturally closes (days 1-5), the only pathway for blood to reach the lower body is through the narrowed coarctation segment — insufficient flow causes acute collapse", "Infection develops", "Feeding intolerance"], a: 1, r: "Fetal life and early neonatal period: PDA provides 'bypass' around the coarctation. As the ductus closes physiologically, the coarctation becomes clinically apparent. This is why CCHD screening in the first 24-48 hours is critical.", s: "Pediatrics" },
  { q: "A child with repaired coarctation has been cleared for activity. The family asks about competitive sports. What specific exercise restriction should the nurse discuss?", o: ["No restrictions at all", "Avoid intense isometric exercise (heavy weightlifting) which causes extreme BP spikes; moderate dynamic exercise is usually allowed. Specific clearance depends on residual findings and exercise stress test results", "Avoid all sports", "Only swimming allowed"], a: 1, r: "Post-coarctation repair: isometric exercise (static, heavy lifting) causes dangerous BP spikes in the upper body. Dynamic exercise (running, swimming) is generally better tolerated. Exercise stress testing guides individual recommendations.", s: "Pediatrics" },
  { q: "A nurse is reviewing imaging for a teenager with newly diagnosed coarctation. CXR shows bilateral rib notching on ribs 3-8. What is the significance of this finding?", o: ["Normal CXR variant", "Dilated intercostal collateral arteries have eroded the inferior rib margins — indicates chronic coarctation with collateral circulation development, confirming the lesion has been present for years", "Rib fractures from abuse", "Osteoporosis"], a: 1, r: "Rib notching from dilated intercostal arteries developing as collateral bypass. Appears after age 5-6. Its presence indicates chronic, hemodynamically significant coarctation that has been present long enough for collateral development.", s: "Pediatrics" },

  // ===== ANTICOAGULATION THERAPY CAT (15 questions) =====
  { q: "A nurse is caring for three anticoagulated clients. Which situation requires the MOST urgent intervention?\n1. Client on warfarin: INR 3.2, no bleeding\n2. Client on heparin drip: aPTT 120 seconds, oozing from IV sites\n3. Client on apixaban: mild epistaxis that stopped with pressure", o: ["Client 1 — INR slightly above range", "Client 2 — significantly supratherapeutic aPTT with active bleeding requiring heparin dose reduction/hold and close monitoring", "Client 3 — minor epistaxis", "All are equally urgent"], a: 1, r: "Client 2: aPTT 120 (therapeutic 60-80) with active bleeding = most urgent. Stop/reduce heparin, monitor for expansion of bleeding, consider protamine if serious. Client 1: slightly high but stable. Client 3: self-resolving.", s: "Pharmacology" },
  { q: "A client on heparin for 8 days has platelets drop from 280K to 95K. The nurse calculates a 66% decline. What SPECIFIC actions must occur immediately?", o: ["Recheck platelets tomorrow", "Stop ALL heparin (including flushes, coated lines), send HIT antibody/SRA testing, start argatroban as alternative anticoagulant, do NOT give platelet transfusions, do NOT start warfarin", "Give more heparin", "Transfuse platelets"], a: 1, r: "HIT II management: (1) Stop ALL heparin (2) Alternative anticoagulant (argatroban) (3) HIT testing (4) NO platelets (fuel thrombosis) (5) NO warfarin until platelets >150K (risk of skin necrosis/gangrene).", s: "Pharmacology" },
  { q: "A client on warfarin is found to have INR 9.5 with no active bleeding. The provider orders oral vitamin K 5 mg. The nurse should also anticipate which monitoring?", o: ["No additional monitoring needed", "Close assessment for new bleeding (melena, hematuria, headache, ecchymoses), hold warfarin, recheck INR in 12-24 hours, and type & screen in case blood products are needed", "Resume warfarin tomorrow", "Give IV vitamin K instead"], a: 1, r: "INR 9.5 without bleeding: oral vitamin K is appropriate (takes 12-24 hours). But high INR carries significant bleeding risk. Close monitoring for any new bleeding, type & screen as precaution, frequent neuro checks.", s: "Pharmacology" },
  { q: "A client on therapeutic enoxaparin develops acute kidney injury (creatinine rises from 1.0 to 3.8). What does the nurse anticipate?", o: ["Continue same enoxaparin dose", "Switch to IV UFH — LMWH accumulates in renal failure, increasing bleeding risk. UFH is cleared by the reticuloendothelial system and is safer in AKI", "Increase enoxaparin dose", "Stop all anticoagulation"], a: 1, r: "LMWH is renally cleared. AKI causes dangerous accumulation and bleeding risk. Switch to UFH (reticuloendothelial clearance, not renal) with aPTT monitoring. This is a critical medication safety consideration.", s: "Pharmacology" },
  { q: "A client with HIT develops an ischemic stroke. This seems contradictory — low platelets should cause bleeding, not clotting. How does the nurse explain this to the healthcare team?", o: ["It is contradictory", "HIT is a PROthrombotic disorder despite low platelets. The antibodies activate platelets, generating massive thrombin and prothrombotic particles. The primary risk is thrombosis, not hemorrhage", "Platelets were miscounted", "Stroke is unrelated to HIT"], a: 1, r: "Key HIT concept: thrombocytopenia occurs because platelets are CONSUMED in clotting, not destroyed by bleeding. HIT antibodies activate platelets → thrombin generation → arterial and venous thrombosis. Risk of thrombosis is 50% if untreated.", s: "Pharmacology" },
  { q: "A client on warfarin has been taking St. John's Wort for depression. The INR has been consistently subtherapeutic (1.3-1.5) despite dose increases. What drug interaction is occurring?", o: ["No interaction", "St. John's Wort induces CYP enzymes, accelerating warfarin metabolism and reducing its anticoagulant effect — requires medication reconciliation", "St. John's Wort increases INR", "Need higher vitamin K intake"], a: 1, r: "St. John's Wort is a potent CYP3A4/CYP2C9 inducer, increasing warfarin clearance. Numerous herbal interactions affect warfarin. Complete medication reconciliation including herbals/supplements is essential.", s: "Pharmacology" },
  { q: "A client on dabigatran (Pradaxa) requires emergent surgery for a ruptured appendix. The specific reversal agent idarucizumab is not available at this hospital. What does the nurse anticipate?", o: ["Wait for idarucizumab transfer", "Proceed with surgery using 4-factor PCC as off-label reversal, activated charcoal if last dose <2 hours ago, and hemodialysis as dabigatran is partially dialyzable", "No reversal options exist", "Give vitamin K"], a: 1, r: "When idarucizumab unavailable for dabigatran reversal: 4-factor PCC (off-label), activated charcoal (if recent ingestion), hemodialysis (dabigatran is 35% protein-bound, partially dialyzable — unique among DOACs). Time-dependent clearance also helps.", s: "Pharmacology" },
  { q: "A nurse is transitioning a client from argatroban (for HIT) to warfarin. The INR is 3.5. Can argatroban be stopped?", o: ["Yes — INR is therapeutic", "No — argatroban artificially elevates INR. The true warfarin effect may be much lower. Continue argatroban until the INR on warfarin alone (after holding argatroban 4-6 hours) is ≥2.0", "Increase argatroban", "Stop both medications"], a: 1, r: "Critical nuance: argatroban (DTI) prolongs PT/INR independently of warfarin. Combined INR will be falsely elevated. Must hold argatroban, recheck INR after 4-6 hours to assess true warfarin effect before discontinuing.", s: "Pharmacology" },
  { q: "A client with a mechanical aortic valve is taking warfarin and needs dental extraction. The dentist requests stopping warfarin. What should the nurse communicate?", o: ["Stop warfarin 5 days before", "Mechanical valve patients are HIGH thrombotic risk — bridge anticoagulation with LMWH is typically needed. The nurse should coordinate between cardiology and dentistry for a perioperative anticoagulation plan", "No anticoagulation changes needed", "Switch to aspirin"], a: 1, r: "Mechanical valves = high thrombotic risk. Perioperative management requires bridge anticoagulation: stop warfarin 5 days before, start LMWH when INR <2, hold LMWH 24 hours pre-procedure, resume post-hemostasis. Interdisciplinary coordination essential.", s: "Pharmacology" },
  { q: "A client on rivaroxaban is hospitalized for acute GI bleeding. The last rivaroxaban dose was 3 hours ago. What is the MOST effective reversal strategy?", o: ["Give vitamin K", "Andexanet alfa (specific Xa reversal) PLUS supportive care (IV fluids, blood products, endoscopy for bleeding source). Activated charcoal may reduce GI absorption if given within 2 hours of last dose", "Give protamine", "Wait for natural clearance"], a: 1, r: "For active bleeding on rivaroxaban: andexanet alfa (specific Xa inhibitor reversal, IV bolus + 2-hour infusion). Charcoal may help if within 2 hours. 4-factor PCC if andexanet unavailable. Supportive care and source control simultaneously.", s: "Pharmacology" },
  { q: "A client with DVT on therapeutic LMWH for 3 days develops sudden hemoptysis and pleuritic chest pain. What is the MOST likely complication?", o: ["Pulmonary embolism despite anticoagulation", "Extension or embolization of the DVT causing pulmonary embolism — this can occur in the first days of anticoagulation before the clot is fully stabilized", "LMWH allergy", "Pneumonia"], a: 1, r: "PE can occur despite adequate anticoagulation in the first days of treatment, as existing clot may still embolize before anticoagulation prevents clot extension. Continue anticoagulation and evaluate with CTA. May need escalation (IVC filter, thrombolysis).", s: "Pharmacology" },
  { q: "A nurse notices a client's warfarin dose has been adjusted 6 times in the past 3 months due to fluctuating INR. The HAS-BLED 'L' (labile INR) component is scored. What should the nurse recommend?", o: ["Continue adjusting warfarin", "Discuss switching to a DOAC with the provider — DOACs eliminate INR monitoring issues and provide more consistent anticoagulation, improving safety", "Increase vitamin K intake", "Stop anticoagulation"], a: 1, r: "Labile INR (TTR <60%) increases both bleeding AND clotting risk. A DOAC would eliminate INR variability while providing consistent anticoagulation. This is an appropriate recommendation if no contraindication (e.g., mechanical valve).", s: "Pharmacology" },
  { q: "A client receiving a heparin infusion develops severe chest tightness, flushing, and hypotension immediately after a protamine dose was given for mild over-anticoagulation. What is happening?", o: ["Expected protamine effect", "Protamine-induced anaphylactoid reaction — risk factors include fish allergy, prior protamine exposure, and vasectomy. Stop protamine, give epinephrine, supportive care", "Heparin reaction", "Coincidental MI"], a: 1, r: "Protamine (derived from fish sperm) can cause anaphylactoid reactions. Risk factors: fish allergy, prior exposure, vasectomy. Presentation: hypotension, flushing, bronchospasm. Treatment: stop protamine, epinephrine, IV fluids, supportive care.", s: "Pharmacology" },
  { q: "A nurse is educating a client who will be on lifelong warfarin for a mechanical valve. The client says 'I eat a lot of vegetables and that's important to me.' Best nursing response?", o: ["You must eliminate all green vegetables", "You can absolutely continue eating vegetables. The key is CONSISTENCY — eat the same approximate amount each week. Your warfarin dose will be adjusted to your usual diet pattern", "Only eat vegetables on alternating days", "Switch to a DOAC so diet doesn't matter"], a: 1, r: "Critical teaching: vitamin K-rich foods don't need to be eliminated — only kept CONSISTENT. The warfarin dose is titrated to the patient's habitual dietary pattern. DOACs are NOT an option for mechanical valves — warfarin is required.", s: "Pharmacology" },
  { q: "A client on therapeutic anticoagulation for VTE wants to travel internationally for 3 weeks. What counseling is MOST important?", o: ["Don't travel", "Carry medication supply for the entire trip, wear medical alert identification, know how to access local healthcare for INR monitoring (if on warfarin) or emergency reversal, and maintain hydration during long flights to prevent DVT recurrence", "No special precautions needed", "Stop anticoagulation for travel"], a: 1, r: "Travel counseling: adequate medication supply, medical alert ID, access to healthcare (INR monitoring abroad if on warfarin), hydration during flights, compression stockings, mobility during long flights, emergency contact information.", s: "Pharmacology" },

  // ===== BLEEDING RISKS & REVERSAL CAT (15 questions) =====
  { q: "A nurse is triaging three bleeding anticoagulated clients:\n1. Client on warfarin: INR 3.8, small bruise on forearm\n2. Client on dabigatran: gross hematuria, Hgb dropping from 11 to 8\n3. Client on enoxaparin: mild gum bleeding with brushing\nPrioritize.", o: ["Client 1 — highest INR", "Client 2 — active significant bleeding with declining hemoglobin requiring reversal with idarucizumab and blood products", "Client 3 — any oral bleeding", "All are equally urgent"], a: 1, r: "Client 2: active significant bleeding (gross hematuria + dropping Hgb) = most urgent. Needs idarucizumab (specific dabigatran reversal), type & cross, possible transfusion. Others have minor bleeding manageable with conservative measures.", s: "Pharmacology" },
  { q: "A septic client develops DIC with fibrinogen 45, platelets 22K, PT 28 sec, and oozing from all IV sites. The provider orders cryoprecipitate, platelets, FFP, and pRBCs. What is the nurse's MOST critical understanding about treatment priorities?", o: ["Blood products will cure DIC", "Blood products are SUPPORTIVE — the underlying cause (sepsis) must be treated simultaneously. Without eliminating the DIC trigger, consumption of transfused products will continue", "Only give one product at a time", "Wait for labs to normalize before treating sepsis"], a: 1, r: "DIC treatment cornerstone: treat the CAUSE (antibiotics for sepsis). Blood products replace consumed factors but will be consumed again if the trigger persists. Both must happen simultaneously.", s: "Pharmacology" },
  { q: "A client on warfarin presents with sudden severe headache, vomiting, and rapidly declining consciousness. INR is 4.2. What is the nurse's HIGHEST priority?", o: ["Check blood glucose", "Suspect intracranial hemorrhage — STAT CT head, IV vitamin K AND 4-factor PCC for immediate INR reversal, neurosurgery consultation, airway protection", "Give oral vitamin K and wait", "Recheck INR"], a: 1, r: "Sudden neurological deterioration on warfarin with elevated INR = ICH until proven otherwise. Time-critical: STAT CT, IMMEDIATE reversal with 4-factor PCC (acts in minutes) + IV vitamin K (sustains reversal), neurosurgery for possible evacuation.", s: "Pharmacology" },
  { q: "A pregnant client at 35 weeks with placental abruption develops DIC (platelets 38K, fibrinogen 65, diffuse bleeding). What is the DEFINITIVE treatment?", o: ["Heparin infusion", "Emergency delivery — the placenta is the source of tissue factor driving the DIC. Removing it stops the cascade. Simultaneously resuscitate with blood products", "Wait for spontaneous resolution", "Only blood products"], a: 1, r: "Obstetric DIC from abruption: placenta releases tissue factor triggering coagulation cascade. Delivery removes the source. Must simultaneously transfuse aggressively (pRBCs, FFP, cryo, platelets) and prepare for possible massive hemorrhage.", s: "Pharmacology" },
  { q: "A client with DIC has schistocytes on blood smear and the team suspects TTP instead. What lab value would help distinguish DIC from TTP?", o: ["D-dimer alone", "Fibrinogen level and PT/aPTT: in DIC, fibrinogen is LOW and PT/aPTT are PROLONGED. In TTP, fibrinogen and coagulation times are NORMAL despite schistocytes and thrombocytopenia", "Only platelet count", "CBC alone"], a: 1, r: "Critical distinction: DIC consumes coagulation factors (low fibrinogen, prolonged PT/aPTT). TTP is a different mechanism (ADAMTS13 deficiency) with normal fibrinogen and coag times. Treatment is completely different (plasma exchange for TTP).", s: "Pharmacology" },
  { q: "A nurse is monitoring a client with DIC. The fibrinogen was 55 mg/dL 4 hours ago and is now 80 mg/dL after cryoprecipitate and antibiotic therapy for sepsis. What does this trend indicate?", o: ["Worsening DIC", "Improving DIC — rising fibrinogen indicates decreased consumption as the underlying cause (sepsis) responds to treatment", "No significance", "Need more cryoprecipitate immediately"], a: 1, r: "Rising fibrinogen is the best indicator of DIC improvement. It means consumption is decreasing (cause being treated) and the liver is replacing fibrinogen. Continue monitoring trend q4-6h to confirm sustained improvement.", s: "Pharmacology" },
  { q: "A client with DIC has declining renal function (creatinine 3.8, oliguria) and digital ischemia (purple, cold fingers). This demonstrates which aspect of DIC pathophysiology?", o: ["Only hemorrhagic component", "The THROMBOTIC component — microvascular thrombi are occluding small vessels in kidneys (AKI) and digits (ischemia), while the hemorrhagic component manifests as oozing and lab coagulopathy", "Medication side effect", "Dehydration"], a: 1, r: "DIC's dual pathology: microvascular thrombosis causes end-organ ischemia (renal failure, digital ischemia, ARDS, hepatic dysfunction) WHILE consumptive coagulopathy causes hemorrhage. Both occur simultaneously.", s: "Pharmacology" },
  { q: "A client with HIT who was started on argatroban 2 days ago now has a therapeutic aPTT. The team wants to start warfarin. When is it safe to start?", o: ["Immediately", "Only when platelets have recovered to >150K — starting warfarin with low platelets in HIT causes catastrophic protein C depletion leading to warfarin-induced skin necrosis and venous limb gangrene", "After 24 hours", "Never"], a: 1, r: "CRITICAL HIT rule: NO warfarin until platelets >150K. In HIT, depleted protein C + warfarin's further protein C depletion = paradoxical hypercoagulable state → skin necrosis, venous limb gangrene. Continue argatroban until platelet recovery.", s: "Pharmacology" },
  { q: "A client on anticoagulation therapy falls and hits their head. CT is normal. The client feels fine. Can the client be safely discharged?", o: ["Yes — CT is normal", "No — anticoagulated patients can develop delayed intracranial hemorrhage. Extended observation (24 hours) or repeat CT in 6-12 hours is recommended even with initial normal CT", "Discharge immediately", "Only if INR is normal"], a: 1, r: "Anticoagulated patients have significant delayed ICH risk after head trauma. Normal initial CT does not exclude delayed hemorrhage. Extended observation with serial neuro checks and possible repeat imaging is the standard of care.", s: "Pharmacology" },
  { q: "A client with massive DIC-related hemorrhage is receiving rapid blood product replacement. After 10 units of pRBCs, the nurse notes the client is developing tremors and ECG changes (prolonged QT). What complication is developing?", o: ["Allergic reaction", "Citrate toxicity causing hypocalcemia — citrate preservative in blood products chelates ionized calcium, causing neuromuscular irritability and cardiac conduction changes", "Hyperkalemia", "Iron overload"], a: 1, r: "Massive transfusion complication: citrate (anticoagulant in blood products) chelates ionized calcium. Symptoms: tremors, tetany, QT prolongation, hypotension. Treat with IV calcium gluconate. Monitor ionized calcium during massive transfusion.", s: "Pharmacology" },
  { q: "A nurse is caring for a client with DIC secondary to acute promyelocytic leukemia (APL). What medication simultaneously treats both the leukemia AND the DIC?", o: ["Standard chemotherapy", "All-trans retinoic acid (ATRA) — induces terminal differentiation of malignant promyelocytes, stopping release of procoagulant granules that trigger DIC", "Heparin infusion", "Cryoprecipitate alone"], a: 1, r: "ATRA is uniquely effective for APL-associated DIC. It forces malignant promyelocytes to mature (differentiate), stopping the release of tissue factor and cancer procoagulant that drive the DIC cascade. Treats root cause.", s: "Pharmacology" },
  { q: "A nurse notes that a client with DIC has petechiae across the trunk AND new-onset digital cyanosis with mottled extremities. How should the nurse document and communicate these findings?", o: ["Document as generalized rash", "Document BOTH hemorrhagic signs (petechiae) AND thrombotic signs (digital ischemia) with exact locations, sizes, and times — this dual presentation confirms active DIC and guides treatment decisions", "Only document the petechiae", "These are unrelated findings"], a: 1, r: "Accurate documentation of BOTH DIC manifestations is critical: hemorrhagic (petechiae, ecchymoses, oozing) AND thrombotic (digital ischemia, mottled skin, oliguria). Tracking both guides treatment balance (blood products vs heparin consideration).", s: "Pharmacology" },
  { q: "A client with chronic DIC from pancreatic cancer develops a DVT while receiving low-dose heparin prophylaxis. What should the nurse understand about this phenomenon?", o: ["Heparin isn't working", "Chronic DIC from malignancy creates a persistent low-grade hypercoagulable state. Standard prophylactic anticoagulation may be insufficient — therapeutic anticoagulation is often needed for cancer-associated VTE", "Cancer patients can't get DVT", "Switch to aspirin"], a: 1, r: "Cancer-associated DIC: chronic low-grade activation creates ongoing thrombotic risk. VTE despite prophylaxis is common. Treatment: therapeutic LMWH (preferred over warfarin in cancer-associated VTE for at least 6 months or duration of cancer treatment).", s: "Pharmacology" },
  { q: "A client with DIC develops acute respiratory distress, bilateral infiltrates on CXR, and PaO2/FiO2 ratio of 180. What organ complication has developed?", o: ["Pneumonia", "ARDS from pulmonary microvascular thrombosis — microthrombi damage the pulmonary endothelium causing increased permeability, edema, and impaired gas exchange", "Heart failure", "Asthma exacerbation"], a: 1, r: "ARDS is a common devastating DIC complication. Pulmonary microthrombi damage the alveolar-capillary membrane, causing non-cardiogenic pulmonary edema and refractory hypoxemia. Requires mechanical ventilation with lung-protective strategies.", s: "Pharmacology" },
  { q: "A client with resolving DIC (fibrinogen trending up, platelets recovering) suddenly develops new deep vein thrombosis. What does the nurse understand about the recovery phase of DIC?", o: ["DIC has recurred", "During DIC recovery, the anticoagulant pathways (protein C, protein S, antithrombin) are still depleted, creating a post-DIC prothrombotic period — VTE prophylaxis may be needed during recovery", "Normal recovery finding", "Resume heparin only if aPTT is low"], a: 1, r: "Post-DIC recovery phase: natural anticoagulants (protein C, S, ATIII) recover more slowly than procoagulant factors, creating a transient hypercoagulable window. VTE prophylaxis during recovery is an important clinical consideration.", s: "Pharmacology" },

  // ===== DIC CAT (15 questions) =====
  { q: "A septic client's labs show: platelets 42K (from 220K), fibrinogen 58 mg/dL, D-dimer >20, PT 24 sec, aPTT 52 sec, schistocytes on smear. The nurse calculates the ISTH DIC score as ≥5. What does this confirm and what is the IMMEDIATE priority?", o: ["Wait for more labs", "Overt DIC confirmed — immediate priority is treating the underlying sepsis (antibiotics) WHILE providing supportive blood product replacement (cryo, platelets, FFP)", "Only give blood products", "Only give antibiotics"], a: 1, r: "ISTH score ≥5 = overt DIC. TWO simultaneous priorities: (1) Treat underlying cause (sepsis = antibiotics) — this is the ONLY way to stop the cascade. (2) Supportive replacement of consumed factors. Neither alone is sufficient.", s: "Pharmacology" },
  { q: "A nurse is monitoring DIC labs serially. The fibrinogen was 45 → 62 → 89 → 115 mg/dL over 24 hours. What does this trend indicate?", o: ["Worsening DIC", "Improving DIC — rising fibrinogen indicates decreased consumption as the underlying cause responds to treatment. This is the BEST indicator of DIC resolution", "No significance", "Need to stop cryoprecipitate"], a: 1, r: "Fibrinogen trend is the best DIC indicator. Rising = improving (consumption decreasing, production recovering). Falling = worsening. Serial monitoring q4-6h guides transfusion needs and treatment effectiveness.", s: "Pharmacology" },
  { q: "A client with DIC from placental abruption at 34 weeks is bleeding massively. Fibrinogen is 38, platelets 28K. The team debates between continuing expectant management vs emergency delivery. What is the DEFINITIVE treatment?", o: ["Continue expectant management with blood products", "Emergency delivery — the placenta is the source of tissue factor driving the DIC cascade. Removing it is the ONLY way to stop the consumption", "Heparin infusion", "Wait for labs to normalize"], a: 1, r: "Obstetric DIC: the placenta (specifically tissue thromboplastin released from abruption) is the TRIGGER. Blood products are supportive but futile without removing the source. Emergency delivery is definitive while simultaneously resuscitating with blood products.", s: "Pharmacology" },
  { q: "A client with DIC has petechiae, oozing IV sites, AND cold mottled digits with absent pulses. The family asks how the patient can be 'bleeding AND clotting at the same time.' How does the nurse explain this?", o: ["They can't — it's two different conditions", "DIC causes widespread tiny clots that use up all clotting factors. The clots block small vessels (causing the cold fingers) while the depleted factors cause bleeding from every other site — it's one process with two consequences", "The medications are conflicting", "The tests are wrong"], a: 1, r: "Explain in lay terms: the body's clotting system is in overdrive, forming thousands of tiny clots everywhere. This uses up all the clotting materials, so the body can't stop bleeding from other sites. It's one disease causing two opposite problems simultaneously.", s: "Pharmacology" },
  { q: "A nurse is caring for a DIC client receiving massive blood product transfusion (12 units pRBCs, 8 FFP, 10 cryo). The client develops facial tingling, muscle cramps, and QT prolongation. What complication is developing?", o: ["Allergic reaction", "Citrate toxicity causing hypocalcemia — citrate preservative in blood products chelates ionized calcium. Give IV calcium gluconate immediately", "Hyperkalemia", "Hypothermia"], a: 1, r: "Massive transfusion complication: citrate chelates ionized calcium → neuromuscular irritability (tingling, cramps, tetany), QT prolongation, hypotension. Monitor ionized calcium, give IV calcium gluconate proactively.", s: "Pharmacology" },
  { q: "A nurse suspects DIC but the team is considering TTP as a differential diagnosis. Both present with thrombocytopenia and schistocytes. What lab result BEST differentiates them?", o: ["Platelet count", "Fibrinogen and PT/aPTT: DIC has LOW fibrinogen and PROLONGED PT/aPTT (consumption of factors). TTP has NORMAL fibrinogen and NORMAL PT/aPTT (no coagulation factor consumption)", "Only D-dimer", "Blood cultures"], a: 1, r: "Critical distinction: DIC = consumptive coagulopathy (low fibrinogen, prolonged clotting times). TTP = platelet consumption WITHOUT coagulation factor involvement (normal fibrinogen, normal PT/aPTT). Treatment is completely different.", s: "Pharmacology" },
  { q: "A client with acute promyelocytic leukemia (APL) develops severe DIC before chemotherapy can be started. What unique medication treats BOTH the leukemia and the DIC simultaneously?", o: ["Standard chemotherapy", "All-trans retinoic acid (ATRA) — forces malignant promyelocytes to differentiate, stopping the release of procoagulant granules that drive the DIC cascade", "Heparin infusion", "Dexamethasone"], a: 1, r: "APL is the prototype of DIC triggered by malignancy. Malignant promyelocytes release tissue factor and cancer procoagulant. ATRA induces terminal differentiation → stops procoagulant release → treats BOTH APL and DIC simultaneously.", s: "Pharmacology" },
  { q: "A client with DIC is oliguric (UOP 10 mL/hr) with creatinine rising from 1.0 to 4.2. What is the cause of the renal failure?", o: ["Dehydration alone", "Renal microvascular thrombosis — DIC microthrombi are occluding the glomerular and renal vasculature, causing ischemic acute kidney injury", "Medication nephrotoxicity", "UTI"], a: 1, r: "Renal microvascular thrombosis: DIC microthrombi lodge in glomerular capillaries → ischemia → AKI. May present with hematuria, oliguria, rising creatinine. Improving DIC by treating the underlying cause is essential; RRT may be needed.", s: "Pharmacology" },
  { q: "During DIC management, the team debates using heparin. In which specific clinical scenario would heparin be MOST appropriate?", o: ["All DIC patients", "When thrombotic manifestations PREDOMINATE (purpura fulminans, digital ischemia, extensive skin necrosis) and hemorrhage is NOT the primary problem", "Never in DIC", "Only for chronic DIC"], a: 1, r: "Heparin in DIC is controversial. May help when thrombosis predominates (purpura fulminans, acral ischemia) to prevent further microvascular occlusion. CONTRAINDICATED when hemorrhage predominates. Clinical judgment is essential.", s: "Pharmacology" },
  { q: "A nurse notes that a client's DIC is caused by a retained dead fetus at 24 weeks. Medical management has stabilized the bleeding temporarily. What is the definitive treatment?", o: ["Continue blood products indefinitely", "Delivery of the fetus to remove the source of tissue thromboplastin that is driving the DIC cascade", "Heparin infusion", "Wait for spontaneous resolution"], a: 1, r: "Retained dead fetus releases tissue thromboplastin → triggers DIC. Like abruption, delivery removes the trigger. Blood product support bridges until delivery. Induction or surgical delivery based on obstetric factors.", s: "Pharmacology" },
  { q: "A nurse is calculating cryoprecipitate needs. The client's fibrinogen is 52 mg/dL and the target is 150 mg/dL. Each unit of cryo raises fibrinogen by approximately 5-10 mg/dL. How many units are needed?", o: ["2-3 units", "10-20 units (need to raise ~100 mg/dL, each unit raises 5-10 mg/dL)", "1 unit", "50 units"], a: 1, r: "Calculation: deficit = 150 - 52 = 98 mg/dL needed. At 5-10 mg/dL per unit: 98/5 to 98/10 = 10-20 units. Typically given as pooled bags of 5-10 units. Recheck fibrinogen 30-60 min after transfusion.", s: "Pharmacology" },
  { q: "A nurse is caring for a neonatal DIC patient caused by meningococcal sepsis. The infant develops rapidly spreading purpura with skin necrosis. What is this called?", o: ["Simple bruising", "Purpura fulminans — rapidly progressive symmetric purpura with skin necrosis from DIC microvascular thrombosis, most commonly associated with meningococcemia", "Drug rash", "Normal neonatal finding"], a: 1, r: "Purpura fulminans: symmetric, rapidly progressive purpuric skin lesions with necrosis from DIC microvascular thrombosis. Most commonly with meningococcal sepsis. Aggressive DIC treatment, antibiotics, and possible surgical debridement/amputation.", s: "Pharmacology" },
  { q: "A client with DIC has been receiving aggressive blood product replacement for 8 hours. Platelets have improved from 22K to 55K and fibrinogen from 45 to 90 mg/dL. However, the underlying sepsis is not yet controlled. What should the nurse expect?", o: ["DIC is cured", "Continued consumption of transfused products — without controlling the septic trigger, the DIC cascade continues consuming whatever is transfused. Treatment of the cause is paramount", "Stop transfusions", "Switch to only FFP"], a: 1, r: "Blood products are consumed by the ongoing DIC cascade if the trigger persists. Improvement is temporary without source control. The critical question is always: is the underlying cause being effectively treated? Antibiotics and source control for sepsis are essential.", s: "Pharmacology" },
  { q: "A client with chronic compensated DIC from pancreatic cancer has near-normal labs but develops a DVT. How does chronic DIC differ from acute DIC?", o: ["Identical presentation", "Chronic DIC has slower activation partially compensated by increased factor production — labs may be near-normal. Presents with THROMBOSIS rather than hemorrhage. Different management approach", "Chronic DIC only causes bleeding", "Chronic DIC is not real"], a: 1, r: "Chronic DIC: slow trigger (malignancy) → liver compensation keeps factors near-normal → presents primarily with thrombosis (DVT, PE). Different from acute DIC (rapid trigger, overwhelmed compensation, hemorrhage). Treatment: anticoagulation + treat cancer.", s: "Pharmacology" },
  { q: "What nursing assessment finding would BEST indicate that DIC treatment is succeeding?", o: ["Patient reports feeling better", "Trending improvement in serial labs: rising fibrinogen, improving platelet count, normalizing PT/aPTT, declining D-dimer, AND clinical improvement (less bleeding, improving organ function)", "Single normal lab value", "Absence of petechiae only"], a: 1, r: "DIC improvement is assessed by TRENDS, not single values: fibrinogen rising (best single marker), platelets recovering, coag times normalizing, D-dimer declining. Clinical correlation: decreased bleeding, improving UOP, better perfusion. Multiple markers must trend together.", s: "Pharmacology" },
];
